/**
 * Unified Blog Engine — SPA, config-driven, zero-build.
 * Architecture: Config → State → DataLoader → Renderer → UI → Router
 *
 * ─────────────────────────────────────────────────────────────────
 *  USAGE
 *  Load a brand config BEFORE this file in your HTML:
 *    <script src="/config-verteil.js"></script>   <!-- or config-shani.js etc. -->
 *    <script src="/script.js"></script>
 *
 *  To add a new brand, copy config-verteil.js, rename it, and fill
 *  in the values. Do NOT edit this file for branding.
 * ─────────────────────────────────────────────────────────────────
 */

if (typeof CONFIG === 'undefined') {
  throw new Error('[Blog Engine] No CONFIG found. Load a brand config script before script.js.');
}

// ── Storage key helper — prevents key collisions on shared origins ─
// All localStorage / sessionStorage keys are prefixed with CONFIG.STORAGE_PREFIX
// (e.g. 'shani') so two blogs on the same domain don't clobber each other.
const _pfx = (CONFIG.STORAGE_PREFIX || 'blogs') + '_';
const _key  = k => _pfx + k;   // e.g. 'shani_theme', 'shani_member'

// ── Tag icons — driven by CONFIG.TAG_ICONS ────────────────────
// Falls back to a built-in set if the config does not provide TAG_ICONS.
const TAG_ICONS = (CONFIG.TAG_ICONS && Object.keys(CONFIG.TAG_ICONS).length)
  ? CONFIG.TAG_ICONS
  : {
      Product:       'fa-solid fa-box-open',
      Engineering:   'fa-solid fa-gears',
      News:          'fa-solid fa-newspaper',
      Release:       'fa-solid fa-rocket',
      Careers:       'fa-solid fa-briefcase',
      Culture:       'fa-solid fa-people-group',
      Partnerships:  'fa-solid fa-handshake',
      Linux:         'fa-brands fa-linux',
      NDC:           'fa-solid fa-plane',
      AWS:           'fa-brands fa-aws',
      DevOps:        'fa-solid fa-gears',
      Platform:      'fa-solid fa-layer-group',
      Incident:      'fa-solid fa-triangle-exclamation',
      Essay:         'fa-solid fa-feather-pointed',
      'Open Source': 'fa-brands fa-osi',
      Post:          'fa-solid fa-file-lines',
    };

// =========================================
// 1. STATE
// =========================================
const AppState = {
  posts: [],
  postsCache: {},
  filter: 'all',
  search: '',
  theme: localStorage.getItem(_key('theme')) || (matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light'),
  isMember: localStorage.getItem(_key('member')) === '1',
  pagination: { page: 1, perPage: CONFIG.POSTS_PER_PAGE || 9 }
};

// ── Validate stored license key silently on page load ─────────
// ── Crypto helpers — SHA-256 via Web Crypto API ───────────────
// We NEVER store the raw license key. We store only a SHA-256 hex
// digest. A stolen localStorage value cannot be reversed to the key.
const LicenseCrypto = {
  async hash(key) {
    const buf = await crypto.subtle.digest(
      'SHA-256',
      new TextEncoder().encode(key.trim())
    );
    return Array.from(new Uint8Array(buf))
      .map(b => b.toString(16).padStart(2, '0')).join('');
  },
  async store(key) {
    const digest = await LicenseCrypto.hash(key);
    localStorage.setItem(_key('license_hash'), digest);
    localStorage.removeItem(_key('license')); // remove any old btoa-encoded key
  },
  clear() {
    localStorage.removeItem(_key('license_hash'));
    localStorage.removeItem(_key('license')); // legacy cleanup
    localStorage.removeItem(_key('member'));
  }
};

// ── Validate stored membership state on page load ─────────────
// We only stored a hash, not the raw key, so we cannot re-hit the
// LS API here. We trust blogs_member and let the next key entry
// re-verify. If the hash is missing but member flag is set, the
// state is corrupt — clear it so it can't grant free access.
(function validateStoredLicense() {
  if (!CONFIG.LEMONSQUEEZY_STORE) return;
  const hasHash  = !!localStorage.getItem(_key('license_hash'));
  const isMember = localStorage.getItem(_key('member')) === '1';
  if (isMember && !hasHash) {
    LicenseCrypto.clear();
    AppState.isMember = false;
  }
})();

// ── View counter — privacy-safe, localStorage only ────────────
const ViewCounter = {
  get(slug) {
    if (CONFIG.VIEW_COUNT_ENABLED === false) return 0;
    return parseInt(localStorage.getItem(_key('views:' + slug)) || '0');
  },
  increment(slug) {
    if (CONFIG.VIEW_COUNT_ENABLED === false) return;
    // Only count once per session per slug to avoid inflation
    const sessionKey = 'view_counted_' + slug;
    if (sessionStorage.getItem(sessionKey)) return;
    sessionStorage.setItem(sessionKey, '1');
    const count = this.get(slug) + 1;
    localStorage.setItem(_key('views:' + slug), count);
    return count;
  },
  fmt(n) {
    if (n >= 1000) return (n / 1000).toFixed(1).replace(/\.0$/, '') + 'k';
    return String(n);
  }
};

// ── Reading streak — consecutive-day visitor tracking ─────────
const ReadingStreak = {
  _key: () => _key('streak'),
  _dkey: () => _key('streak_date'),
  get() {
    return parseInt(localStorage.getItem(this._key()) || '0');
  },
  update() {
    if (CONFIG.STREAK_ENABLED === false) return;
    const today = new Date().toDateString();
    const last  = localStorage.getItem(this._dkey());
    if (last === today) return; // already counted today
    const yesterday = new Date(Date.now() - 86400000).toDateString();
    const streak = last === yesterday ? this.get() + 1 : 1;
    localStorage.setItem(this._key(), streak);
    localStorage.setItem(this._dkey(), today);
    return streak;
  },
  render() {
    if (CONFIG.STREAK_ENABLED === false) return;
    const streak = this.get();
    if (streak < 2) return; // only show after 2+ days
    const existing = document.getElementById('streak-badge');
    if (existing) return;
    const badge = document.createElement('span');
    badge.id = 'streak-badge';
    badge.className = 'streak-badge';
    badge.title = `You've visited ${streak} days in a row!`;
    badge.innerHTML = `🔥 <span>${streak}</span>`;
    const actions = document.querySelector('.header__actions');
    if (actions) actions.insertBefore(badge, actions.firstChild);
  }
};

// ── Relative date helper ──────────────────────────────────────
const RelDate = {
  fmt(dateStr) {
    const d   = new Date(dateStr + 'T00:00:00');
    const now = new Date();
    if (isNaN(d)) return '';
    const diff = Math.floor((now - d) / 1000);
    if (diff < 3600)   return 'just now';
    if (diff < 86400)  return `${Math.floor(diff / 3600)}h ago`;
    const days  = Math.floor(diff / 86400);
    if (days < 7)   return `${days}d ago`;
    if (days < 30)  return `${Math.floor(days / 7)}w ago`;
    if (days < 365) return `${Math.floor(days / 30)}mo ago`;
    return `${Math.floor(days / 365)}y ago`;
  }
};

// ── Word count helper ─────────────────────────────────────────
const WordCount = {
  count(body) {
    return body ? body.trim().split(/\s+/).filter(Boolean).length : 0;
  },
  fmt(n) {
    if (n >= 1000) return (n / 1000).toFixed(1).replace(/\.0$/, '') + 'k words';
    return n + ' words';
  }
};


// ── Recently viewed posts tracker ─────────────────────────────
const RecentlyViewed = {
  _key: () => _key('recently_viewed'),
  get() {
    try { return JSON.parse(localStorage.getItem(this._key()) || '[]'); } catch { return []; }
  },
  add(slug) {
    if (!CONFIG.RECENTLY_VIEWED_COUNT) return;
    const max = CONFIG.RECENTLY_VIEWED_COUNT || 5;
    const list = this.get().filter(s => s !== slug);
    list.unshift(slug);
    localStorage.setItem(this._key(), JSON.stringify(list.slice(0, max)));
  },
  getPosts() {
    return this.get()
      .map(slug => AppState.posts.find(p => p.slug === slug))
      .filter(Boolean);
  }
};

// =========================================
// 2. UTILS
// =========================================
const Utils = {
  qs: (sel, root) => (root || document).querySelector(sel),
  escapeHtml: str => String(str)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;')
    .replace(/>/g, '&gt;').replace(/"/g, '&quot;')
    .replace(/'/g, '&#39;'),
  // safeText — use for text nodes rendered via innerHTML (NOT attributes).
  // Only escapes & < > so apostrophes and quotes display correctly.
  safeText: str => String(str)
    .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;'),
  fmtDate: str => {
    const d = new Date(str + 'T00:00:00');
    const locale = CONFIG.DATE_LOCALE || 'en-US';
    return isNaN(d) ? str : d.toLocaleDateString(locale, { month: 'long', day: 'numeric', year: 'numeric' });
  },
  fmtDateShort: str => {
    const d = new Date(str + 'T00:00:00');
    const locale = CONFIG.DATE_LOCALE || 'en-US';
    return isNaN(d) ? str : d.toLocaleDateString(locale, { month: 'short', day: 'numeric', year: 'numeric' });
  },
  tagIcon: tag => `<i class="${TAG_ICONS[tag] || TAG_ICONS.Post}" aria-hidden="true"></i>`,
  parseFrontmatter: raw => {
    const md = raw.replace(/^\uFEFF/, '');
    const match = md.match(/^---\r?\n([\s\S]*?)\r?\n---\r?\n?([\s\S]*)$/);
    if (!match) return { fm: {}, body: md };
    const fm = {};
    match[1].split(/\r?\n/).forEach(line => {
      const i = line.indexOf(':');
      if (i < 1) return;
      fm[line.slice(0, i).trim()] = line.slice(i + 1).trim().replace(/^['"`]|['"`]$/g, '');
    });
    return { fm, body: match[2] };
  },
  slugify: text => text.toLowerCase()
    .replace(/[^\w\s-]/g, '').trim()
    .replace(/[\s_]+/g, '-').replace(/-+/g, '-'),
  CALLOUT_TYPES: {
    NOTE:      { icon: 'fa-solid fa-circle-info',          cls: 'callout-note'      },
    TIP:       { icon: 'fa-solid fa-lightbulb',            cls: 'callout-tip'       },
    WARNING:   { icon: 'fa-solid fa-triangle-exclamation', cls: 'callout-warning'   },
    CAUTION:   { icon: 'fa-solid fa-fire',                 cls: 'callout-caution'   },
    IMPORTANT: { icon: 'fa-solid fa-star',                 cls: 'callout-important' },
  },
  renderMath(html) {
    if (typeof katex === 'undefined') return html;
    const parts = html.split(/(<pre[\s\S]*?<\/pre>|<code[\s\S]*?<\/code>)/);
    return parts.map((part, i) => {
      if (i % 2 === 1) return part;
      part = part.replace(/\$\$([\s\S]+?)\$\$/g, (_, expr) => {
        try { return katex.renderToString(expr.trim(), { displayMode: true, throwOnError: false }); }
        catch { return ''; }
      });
      part = part.replace(/(?<!\$)\$([^\n$]+?)\$(?!\$)/g, (_, expr) => {
        try { return katex.renderToString(expr.trim(), { displayMode: false, throwOnError: false }); }
        catch { return ''; }
      });
      return part;
    }).join('');
  },
  // ─── MEDIA SHORTCODES ─────────────────────────────────────────
  _mediaBlocks: {},
  _mediaToken(html) {
    const key = `MBLOCK_${Object.keys(Utils._mediaBlocks).length}_END`;
    Utils._mediaBlocks[key] = html;
    return '\n\n' + key + '\n\n';
  },
  _cap: raw => {
    const pipe = raw.lastIndexOf('|');
    return pipe === -1
      ? { val: raw.trim(), caption: '' }
      : { val: raw.slice(0, pipe).trim(), caption: raw.slice(pipe + 1).trim() };
  },
  _youtube(id, caption) {
    const fig = caption ? `<figcaption>${caption}</figcaption>` : '';
    return `<figure class="media-embed"><div class="media-embed__ratio"><iframe src="https://www.youtube-nocookie.com/embed/${id}" title="${caption || 'YouTube video'}" loading="lazy" allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" allowfullscreen></iframe></div>${fig}</figure>`;
  },
  _vimeo(id, caption) {
    const fig = caption ? `<figcaption>${caption}</figcaption>` : '';
    return `<figure class="media-embed"><div class="media-embed__ratio"><iframe src="https://player.vimeo.com/video/${id}?dnt=1" title="${caption || 'Vimeo video'}" loading="lazy" allow="autoplay; fullscreen; picture-in-picture" allowfullscreen></iframe></div>${fig}</figure>`;
  },
  _video(src, caption) {
    const fig  = caption ? `<figcaption>${caption}</figcaption>` : '';
    const ext  = src.split('?')[0].split('.').pop().toLowerCase();
    const mime = { mp4: 'video/mp4', webm: 'video/webm', ogg: 'video/ogg', mov: 'video/mp4' }[ext] || 'video/mp4';
    return `<figure class="media-figure media-figure--video"><video controls preload="metadata" playsinline loading="lazy"><source src="${src}" type="${mime}">Your browser doesn't support HTML video. <a href="${src}">Download it</a>.</video>${fig}</figure>`;
  },
  _audio(src, caption) {
    const fig = caption ? `<figcaption>${caption}</figcaption>` : '';
    return `<figure class="media-figure media-figure--audio"><audio controls preload="metadata" loading="lazy"><source src="${src}">Your browser doesn't support HTML audio. <a href="${src}">Download it</a>.</audio>${fig}</figure>`;
  },
  _image(src, rest) {
    const parts   = rest.split('|').map(s => s.trim());
    const alt     = parts[0] || '';
    const caption = parts[1] !== undefined ? parts[1] : alt;
    const wide    = parts[2] === 'wide';
    const fig     = caption ? `<figcaption>${caption}</figcaption>` : '';
    return `<figure class="media-figure${wide ? ' media-figure--wide' : ''}"><img src="${src}" alt="${alt}" loading="lazy">${fig}</figure>`;
  },
  // ─── Strip manual TOC block from raw markdown (for preview counting) ───
  _stripTocBlock(text) {
    return text
      .replace(/^#{1,3}\s+(?:table\s+of\s+)?contents?\s*\n[\s\S]*?(?=\n(?=#{1,3}\s))/im, '')
      .replace(/^\[\[?toc\]?\]\s*$/im, '')
      .trim();
  },

  // ─── TABLE OF CONTENTS ────────────────────────────────────────
  _buildToc(text) {
    // Extract h2/h3 headings (h1 is the post title, skip it)
    const headings = [];
    const re = /^(#{2,3})\s+(.+)$/gm;
    let m;
    while ((m = re.exec(text)) !== null) {
      const level = m[1].length;
      const raw   = m[2]
        .replace(/\[([^\]]*)\]\([^)]*\)/g, '$1') // links: keep label, drop URL
        .replace(/\*+|`|_+|~+/g, '')             // bold, italic, code, strikethrough
        .trim();
      // Skip the TOC heading itself
      if (/^(?:table\s+of\s+)?contents?$/i.test(raw)) continue;
      const id    = Utils.slugify(raw);
      headings.push({ level, text: raw, id });
    }
    if (headings.length < 2) return '';
    let html = '<nav class="toc" aria-label="Table of contents"><p class="toc__title"><i class="fa-solid fa-list-ul" aria-hidden="true"></i> Contents</p><ol class="toc__list">';
    let inSub = false;
    headings.forEach((h, i) => {
      if (h.level === 2) {
        if (inSub) { html += '</li></ol></li>'; inSub = false; }
        else if (i > 0) html += '</li>';
        html += `<li class="toc__item"><a href="#${h.id}">${h.text}</a>`;
      } else {
        if (!inSub) { html += '<ol class="toc__sub">'; inSub = true; }
        else html += '</li>';
        html += `<li class="toc__item toc__item--sub"><a href="#${h.id}">${h.text}</a>`;
      }
    });
    if (inSub) html += '</li></ol></li>';
    else html += '</li>';
    html += '</ol></nav>';
    return html;
  },

  _processShortcodes(text) {
    Utils._mediaBlocks = {};
    // ── [toc] / [[toc]] shortcode ─────────────────────────────
    if (/\[\[?toc\]?\]/i.test(text)) {
      const tocHtml = Utils._buildToc(text);
      text = text.replace(/\[\[?toc\]?\]/gi, tocHtml ? Utils._mediaToken(tocHtml) : '');
    }
    // ── Auto-detect manual "## Table of Contents" block ───────
    // Matches: optional h2/h3 heading containing "table of contents" / "contents"
    // followed by a markdown list of links — strips it and replaces with styled TOC
    text = text.replace(
      /^#{1,3}\s+(?:table\s+of\s+)?contents?\s*\n[\s\S]*?(?=\n(?=#{1,3}\s))/im,
      (match) => {
        const tocHtml = Utils._buildToc(text);
        return tocHtml ? Utils._mediaToken(tocHtml) : '';
      }
    );
    text = text.replace(/::youtube\[([^\]]+)\]/g, (_, raw) => {
      const { val, caption } = Utils._cap(raw);
      return Utils._mediaToken(Utils._youtube(val, caption));
    });
    text = text.replace(/::vimeo\[([^\]]+)\]/g, (_, raw) => {
      const { val, caption } = Utils._cap(raw);
      return Utils._mediaToken(Utils._vimeo(val, caption));
    });
    text = text.replace(/::video\[([^\]]+)\]/g, (_, raw) => {
      const { val, caption } = Utils._cap(raw);
      return Utils._mediaToken(Utils._video(val, caption));
    });
    text = text.replace(/::audio\[([^\]]+)\]/g, (_, raw) => {
      const { val, caption } = Utils._cap(raw);
      return Utils._mediaToken(Utils._audio(val, caption));
    });
    text = text.replace(/::image\[([^\]]+)\]/g, (_, raw) => {
      const first = raw.indexOf('|');
      const src   = first === -1 ? raw.trim() : raw.slice(0, first).trim();
      const rest  = first === -1 ? '' : raw.slice(first + 1);
      return Utils._mediaToken(Utils._image(src, rest));
    });
    return text;
  },
  _restoreShortcodes(html) {
    html = html.replace(/<p>(MBLOCK_\d+_END)<\/p>/g, (_, token) => Utils._mediaBlocks[token] || '');
    html = html.replace(/MBLOCK_\d+_END/g, token => Utils._mediaBlocks[token] || '');
    return html;
  },
  safeMarkdown: text => {
    if (typeof marked !== 'undefined') {
      text = Utils._processShortcodes(text);
      const renderer = new marked.Renderer();

      renderer.code = (codeOrToken, lang) => {
        // marked@4 passes a token object; marked@2/3 passes (code, lang) strings.
        const code = (codeOrToken && typeof codeOrToken === 'object') ? codeOrToken.text : codeOrToken;
        const rawLang = (codeOrToken && typeof codeOrToken === 'object') ? codeOrToken.lang : lang;
        const safeLang = ((rawLang || '').split(/\s/)[0]);
        const cls = safeLang ? `class="language-${safeLang}"` : '';
        const escaped = (code || '')
          .replace(/&/g, '&amp;')
          .replace(/</g, '&lt;')
          .replace(/>/g, '&gt;')
          .replace(/"/g, '&quot;');
        return `<pre><code ${cls}>${escaped}</code></pre>\n`;
      };

      renderer.heading = (textOrToken, level) => {
        // marked@4 passes a token object; marked@2/3 passes (text, level).
        const text  = (textOrToken && typeof textOrToken === 'object') ? (textOrToken.text || '') : textOrToken;
        const depth = (textOrToken && typeof textOrToken === 'object') ? textOrToken.depth : level;
        const plain = text.replace(/<[^>]+>/g, '').replace(/\[([^\]]*)\]\([^)]*\)/g, '$1');
        const id = Utils.slugify(plain);
        return `<h${depth} id="${id}">${text}<a class="heading-anchor" href="#${id}" aria-hidden="true">#</a></h${depth}>\n`;
      };

      renderer.link = (hrefOrToken, title, linkText) => {
        // marked@4 passes a token object; marked@2/3 passes (href, title, text).
        const href     = (hrefOrToken && typeof hrefOrToken === 'object') ? hrefOrToken.href  : hrefOrToken;
        const ttl      = (hrefOrToken && typeof hrefOrToken === 'object') ? hrefOrToken.title : title;
        const txt      = (hrefOrToken && typeof hrefOrToken === 'object') ? hrefOrToken.text  : linkText;
        const isExternal = href && !href.startsWith('#') && !href.startsWith('/');
        const t = ttl ? ` title="${ttl}"` : '';
        const ext = isExternal ? ` target="_blank" rel="noopener noreferrer"` : '';
        return `<a href="${href}"${t}${ext}>${txt}</a>`;
      };

      renderer.image = (srcOrToken, title, alt) => {
        // marked@4 passes a token object; marked@2/3 passes (src, title, alt).
        const src     = (srcOrToken && typeof srcOrToken === 'object') ? srcOrToken.href  : srcOrToken;
        const ttl     = (srcOrToken && typeof srcOrToken === 'object') ? srcOrToken.title : title;
        const altText = (srcOrToken && typeof srcOrToken === 'object') ? srcOrToken.text  : alt;
        const t       = ttl ? ` title="${ttl}"` : '';
        const caption = altText || ttl;
        const fig     = caption ? `<figcaption>${caption}</figcaption>` : '';
        return `<figure class="media-figure"><img src="${src}" alt="${altText || ''}"${t} loading="lazy">${fig}</figure>`;
      };

      renderer.blockquote = (quoteOrToken) => {
        // marked@4 passes a token object with .text; marked@2/3 passes an HTML string.
        const quote = (quoteOrToken && typeof quoteOrToken === 'object')
          ? (quoteOrToken.body || quoteOrToken.text || '')
          : quoteOrToken;
        const match = quote.match(/^<p>\[!(NOTE|TIP|WARNING|CAUTION|IMPORTANT)\]([\s\S]*)/i);
        if (match) {
          const type = match[1].toUpperCase();
          const cfg  = Utils.CALLOUT_TYPES[type] || Utils.CALLOUT_TYPES.NOTE;
          const body = match[2].replace(/<\/p>$/, '').replace(/^(\s*<br\s*\/?>\s*|\n)/i, '').trim();
          return `<div class="callout ${cfg.cls}" role="note"><div class="callout__title"><i class="${cfg.icon}" aria-hidden="true"></i>${type}</div><div class="callout__body">${body}</div></div>\n`;
        }
        return `<blockquote>${quote}</blockquote>\n`;
      };

      let raw = marked.parse(text, { renderer, gfm: true, breaks: false });
      raw = Utils.renderMath(raw);

      if (typeof DOMPurify !== 'undefined') {
        raw = DOMPurify.sanitize(raw, {
          ADD_TAGS: ['pre', 'code', 'span', 'video', 'audio', 'source', 'iframe',
                     'details', 'summary', 'input', 'figure', 'figcaption',
                     'table', 'thead', 'tbody', 'tfoot', 'tr', 'th', 'td',
                     'math', 'annotation', 'semantics', 'mrow', 'mi', 'mn',
                     'mo', 'msup', 'msub', 'mfrac', 'mspace', 'mtext'],
          ADD_ATTR: ['class', 'id', 'src', 'controls', 'autoplay', 'loop', 'muted',
                     'playsinline', 'width', 'height', 'allow', 'allowfullscreen',
                     'frameborder', 'loading', 'type', 'checked', 'disabled',
                     'target', 'rel', 'title', 'alt', 'scope', 'align',
                     'encoding', 'display', 'style', 'aria-hidden', 'preload',
                     'poster', 'dnt']
        });
      }

      return Utils._restoreShortcodes(raw);
    }
    return text.replace(/\n/g, '<br>');
  },
  readTime: body => { const wpm = CONFIG.WORDS_PER_MINUTE || 200; return `${Math.max(1, Math.ceil(body.trim().split(/\s+/).length / wpm))} min`; }
};

// =========================================
// 3. DATA LOADER
// =========================================
// Post discovery priority (highest → lowest):
//   1. posts/manifest.json  — pre-built by GitHub Actions (preferred, no API calls)
//   2. GitHub Contents API  — fallback when manifest is absent (60 req/hr unauthenticated)
//   3. posts/index.json     — local dev fallback
//
// A GitHub token is NEVER stored in config or shipped to the browser.
// If you need to raise the rate limit or access a private repo, deploy
// a Cloudflare Worker proxy and set CONFIG.POSTS_API_URL to its URL.
const DataLoader = {
  // ── Normalise a raw manifest/index item into a post record ───
  // When manifest.json is built by GitHub Actions it includes the full
  // post body (or a preview for paywalled posts) — so the browser never
  // needs a second fetch just to open a post.
  _normalise(item) {
    const post = {
      slug:           item.slug           || '',
      title:          item.title          || 'Untitled',
      excerpt:        item.excerpt        || '',
      date:           item.date           || new Date().toISOString().split('T')[0],
      tag:            item.tag            || 'Post',
      readTime:       item.readTime       || '1 min',
      paywalled:      item.paywalled === true || item.paywalled === 'true',
      cover:          item.cover          || '',
      series:         item.series         || '',
      author:         item.author         || CONFIG.AUTHOR_NAME,
      authorRole:     item.author_role    || CONFIG.AUTHOR_ROLE,
      authorBio:      item.author_bio     || CONFIG.AUTHOR_BIO,
      authorInitials: item.author_initials || CONFIG.AUTHOR_INITIALS || (
        (item.author || CONFIG.AUTHOR_NAME)
          .split(' ').map(w => w[0]).join('').toUpperCase().slice(0, 2)
      ),
      authorLinkedin: item.author_linkedin || '',
      authorGithub:   item.author_github   || '',
      authorWebsite:  item.author_website  || '',
    };
    // Manifest is metadata-only — body is fetched on-demand when a post is opened.
    // If body is present (e.g. legacy manifest or local dev index.json with body),
    // cache it immediately so fetchBody() returns without a network request.
    if (item.body !== undefined) {
      post.body           = item.body;
      post._previewCached = item._previewCached === true;
      AppState.postsCache[post.slug] = post;
    }
    return post;
  },

  // ── _fetchMd: fetch + parse one .md file into a post metadata record ──
  // body is intentionally NOT cached here — only stored on-demand in fetchBody().
  async _fetchMd(name, base) {
    const r = await fetch(`${base}/${name}`);
    if (!r.ok) throw new Error(`HTTP ${r.status}`);
    const { fm, body } = Utils.parseFrontmatter(await r.text());
    const slug = name.replace(/\.md$/, '');
    const isPaywalled = fm.paywalled === 'true';
    return {
      slug,
      title:   fm.title || 'Untitled',
      excerpt: fm.excerpt || (() => {
        const excerptSrc = isPaywalled
          ? (body.split(/\n\n+/).find(l => l.trim() && !l.startsWith('#')) || body)
          : body;
        const s = excerptSrc
          .replace(/```[\s\S]*?```/g, '').replace(/`[^`]+`/g, '')
          .replace(/!?\[[^\]]*\]\([^)]*\)/g, '')
          .replace(/[*_~]{1,3}([^*_~]+)[*_~]{1,3}/g, '$1')
          .replace(/^#{1,6}\s+/gm, '').replace(/^>\s*/gm, '')
          .replace(/^[-*+]\s+/gm, '').replace(/\n/g, ' ').trim();
        const _emc = CONFIG.EXCERPT_MAX_CHARS || 140; return s.substring(0, _emc) + (s.length > _emc ? '\u2026' : '');
      })(),
      date:           fm.date     || new Date().toISOString().split('T')[0],
      tag:            fm.tag      || 'Post',
      readTime:       fm.readTime || Utils.readTime(body),
      paywalled:      isPaywalled,
      cover:          fm.cover    || '',
      series:         fm.series   || '',
      author:         fm.author         || CONFIG.AUTHOR_NAME,
      authorRole:     fm.author_role    || CONFIG.AUTHOR_ROLE,
      authorBio:      fm.author_bio     || CONFIG.AUTHOR_BIO,
      authorInitials: fm.author_initials || CONFIG.AUTHOR_INITIALS || (
        (fm.author || CONFIG.AUTHOR_NAME).split(' ').map(w => w[0]).join('').toUpperCase().slice(0, 2)
      ),
      authorLinkedin: fm.author_linkedin || '',
      authorGithub:   fm.author_github   || '',
      authorWebsite:  fm.author_website  || '',
      // body NOT stored — fetched on-demand by fetchBody()
    };
  },

  // ── _fetchBatch: fetch .md files with capped concurrency ──────────
  // With hundreds of posts, firing 200 simultaneous fetches would
  // saturate the browser connection pool. Process in batches of 12.
  async _fetchBatch(filenames, base, batchSize = 12) {
    const results = [];
    for (let i = 0; i < filenames.length; i += batchSize) {
      const batch = filenames.slice(i, i + batchSize);
      const settled = await Promise.allSettled(batch.map(name => this._fetchMd(name, base)));
      for (const r of settled) {
        if (r.status === 'fulfilled') results.push(r.value);
        else console.warn('[DataLoader] Failed to load a post:', r.reason?.message);
      }
    }
    return results;
  },

  async load() {
    // ── file:// local dev ──────────────────────────────────────
    // Browsers block fetch() on file:// origins. Serve via a local
    // HTTP server instead:
    //   python3 -m http.server 8080       # then open http://localhost:8080
    //   npx serve .                        # alternative
    //   npx http-server -p 8080 -c-1      # alternative (no cache)
    if (location.protocol === 'file:') {
      UI.showError(
        'Open via a local dev server',
        'Browsers block fetch() on file:// URLs. Start a local server in your repo root:',
        'python3 -m http.server 8080\n# then open http://localhost:8080'
      );
      return null;
    }

    // ── Resolve the base URL for post files ────────────────────
    // Priority:
    //   1. CONFIG.POSTS_BASE_URL  — explicit override (Cloudflare R2, custom CDN, etc.)
    //   2. Same origin (/posts)   — works for BOTH public AND private GitHub Pages repos.
    //      The Pages site is always publicly served even when the source repo is private.
    //   3. raw.githubusercontent.com — NOT used as default (requires auth on private repos).
    //      Set CONFIG.POSTS_BASE_URL explicitly if needed.
    const base = CONFIG.POSTS_BASE_URL || '/posts';

    // ── 1. Try manifest.json first (built by GitHub Actions) ─────
    // manifest.json is metadata-only (no body). ~100 KB for hundreds of posts.
    // Body is fetched on-demand when the reader opens a post (see fetchBody).
    try {
      const r = await fetch(`${base}/manifest.json`, { cache: 'no-cache' });
      if (r.ok) {
        const list = await r.json();
        if (Array.isArray(list) && list.length > 0 && typeof list[0] === 'object') {
          return list.map(item => this._normalise(item))
                     .sort((a, b) => new Date(b.date) - new Date(a.date));
        }
      }
    } catch { /* manifest not present yet — fall through to next strategy */ }

    // ── Detect local dev environment ──────────────────────────
    // python3 -m http.server, npx serve, etc. all run on localhost.
    // On localhost we never call the GitHub API — it would either rate-limit
    // or 404 on private repos. Instead we scan posts/ directly.
    const isLocalDev = ['localhost', '127.0.0.1', '0.0.0.0', '::1'].includes(location.hostname)
      || location.hostname.startsWith('192.168.')
      || location.hostname.endsWith('.local');

    let filenames;

    if (!isLocalDev && CONFIG.GITHUB_USER && CONFIG.GITHUB_REPO) {
      // ── 2. Fallback: GitHub Contents API (unauthenticated, 60 req/hr) ──
      // Only reached on production when manifest.json doesn't exist yet
      // (first deploy before the Action has run). Once the Action runs once,
      // manifest.json is written and this path is never reached again.
      try {
        const apiUrl = CONFIG.POSTS_API_URL ||
          `https://api.github.com/repos/${CONFIG.GITHUB_USER}/${CONFIG.GITHUB_REPO}/contents/posts`;
        const r = await fetch(apiUrl, { headers: { 'Accept': 'application/vnd.github.v3+json' } });
        if (!r.ok) throw new Error(`GitHub API HTTP ${r.status}`);
        const entries = await r.json();
        filenames = entries
          .filter(e => e.type === 'file' && e.name.endsWith('.md') && e.name !== 'index.md' && e.name !== 'manifest.json')
          .map(e => e.name);
      } catch (e) {
        UI.showError(
          'Could not list posts',
          e.message,
          'Tip: push once to trigger the GitHub Action — it writes posts/manifest.json and this fallback is never needed again.'
        );
        return null;
      }
    } else {
      // ── 3. Local dev: discover posts without GitHub API ───────
      // Strategy A: posts/manifest.json — already handled above (strategy 1).
      //   Run `node generate-manifest.js` once to create it, then just refresh.
      // Strategy B: posts/index.json — a simple filename list you maintain.
      // Strategy C: parse the directory listing from python3 -m http.server.
      //   No extra files needed — works out of the box.

      // Try index.json first (explicit list, fastest)
      try {
        const r = await fetch(`${base}/index.json`);
        if (r.ok) {
          const list = await r.json();
          if (Array.isArray(list)) {
            if (list.length > 0 && typeof list[0] === 'object' && list[0] !== null) {
              return list.map(item => this._normalise(item))
                         .sort((a, b) => new Date(b.date) - new Date(a.date));
            }
            filenames = list.filter(n => typeof n === 'string' && n.endsWith('.md'));
          }
        }
      } catch { /* no index.json — fall through to directory listing */ }

      // Parse the HTML directory listing served by python3 -m http.server
      if (!filenames) {
        try {
          const r = await fetch(`${base}/`);
          if (!r.ok) throw new Error(`HTTP ${r.status}`);
          const html = await r.text();
          // Extract all href values ending in .md from the directory listing
          const matches = [...html.matchAll(/href="([^"]+\.md)"/g)];
          filenames = matches
            .map(m => decodeURIComponent(m[1]).replace(/^.*\//, '')) // basename only
            .filter(n => n !== 'index.md');
          if (filenames.length === 0) throw new Error('No .md files found in posts/ directory listing.');
        } catch (e) {
          UI.showError(
            'Local dev: could not discover posts',
            'Run this once in your repo root to generate posts/manifest.json, then refresh:',
            'node generate-manifest.js'
          );
          return null;
        }
      }
    }

    // ── Fetch .md files in batches of 12 (connection-pool friendly) ─
    const posts = await this._fetchBatch(filenames, base);
    return posts.sort((a, b) => new Date(b.date) - new Date(a.date));
  },

  async fetchBody(slug) {
    // ── Cache check ───────────────────────────────────────────
    // Normal path (manifest.json exists): body is NOT in the manifest.
    // We fetch the .md file the first time the reader opens a post,
    // then cache it in AppState.postsCache for instant re-opens.
    const cached = AppState.postsCache[slug];
    if (cached) {
      // Body already present and correct for the current membership state
      if (!cached.paywalled && cached.body !== undefined) return cached;
      if (cached.paywalled && AppState.isMember && !cached._previewCached) return cached;
      if (cached.paywalled && !AppState.isMember && cached._previewCached) return cached;
      // Body missing (metadata-only from manifest) — fall through to fetch
    }

    const base = CONFIG.POSTS_BASE_URL || '/posts';
    const r = await fetch(`${base}/${slug}.md`);
    if (!r.ok) throw new Error(`HTTP ${r.status} — could not load ${slug}.md`);

    const { fm, body } = Utils.parseFrontmatter(await r.text());
    const meta = AppState.posts.find(p => p.slug === slug) || {};
    const isPaywalled = fm.paywalled === 'true' || meta.paywalled;
    const _ppb = CONFIG.PAYWALL_PREVIEW_BLOCKS || 12; const previewBody = Utils._stripTocBlock(body).split(/\n\n+/).slice(0, _ppb).join('\n\n');
    const full = {
      slug,
      title:          fm.title           || meta.title          || 'Untitled',
      excerpt:        fm.excerpt          || meta.excerpt         || '',
      date:           fm.date             || meta.date            || '',
      tag:            fm.tag              || meta.tag             || 'Post',
      readTime:       fm.readTime         || meta.readTime        || Utils.readTime(body),
      paywalled:      isPaywalled,
      cover:          fm.cover            || meta.cover           || '',
      series:         fm.series           || meta.series          || '',
      author:         fm.author           || meta.author          || CONFIG.AUTHOR_NAME,
      authorRole:     fm.author_role      || meta.authorRole      || CONFIG.AUTHOR_ROLE,
      authorBio:      fm.author_bio       || meta.authorBio       || CONFIG.AUTHOR_BIO,
      authorInitials: fm.author_initials  || meta.authorInitials  || CONFIG.AUTHOR_INITIALS,
      authorLinkedin: fm.author_linkedin  || meta.authorLinkedin  || '',
      authorGithub:   fm.author_github    || meta.authorGithub    || '',
      authorWebsite:  fm.author_website   || meta.authorWebsite   || '',
      body: (isPaywalled && !AppState.isMember) ? previewBody : body,
      _previewCached: (isPaywalled && !AppState.isMember)
    };
    AppState.postsCache[slug] = full;
    return full;
  }
};

// =========================================
// 4. RENDERER
// =========================================
const Renderer = {
  // ── Inject all brand strings from CONFIG into the DOM ────────
  applyBranding() {
    const fullTitle = `${CONFIG.SITE_TITLE} — ${CONFIG.SITE_TAGLINE}`;
    document.title = fullTitle;

    // Canonical + OG URLs
    document.getElementById('canonical-url')?.setAttribute('href', `${CONFIG.BLOG_URL}/`);
    document.getElementById('og-url')?.setAttribute('content', `${CONFIG.BLOG_URL}/`);
    document.getElementById('og-type')?.setAttribute('content', 'website');

    // Titles & descriptions
    ['og-title', 'tw-title'].forEach(id =>
      Utils.qs(`#${id}`)?.setAttribute('content', fullTitle));
    ['og-desc', 'tw-desc'].forEach(id =>
      Utils.qs(`#${id}`)?.setAttribute('content', CONFIG.SITE_DESCRIPTION));
    document.getElementById('meta-desc')?.setAttribute('content', CONFIG.SITE_DESCRIPTION);

    // Keywords meta
    if (CONFIG.SITE_KEYWORDS) {
      document.getElementById('meta-keywords')?.setAttribute('content', CONFIG.SITE_KEYWORDS);
    }

    // OG site name
    document.getElementById('og-site-name')?.setAttribute('content', CONFIG.SITE_TITLE);

    // OG image + alt
    document.getElementById('og-image')?.setAttribute('content', CONFIG.OG_IMAGE);
    document.getElementById('og-image-alt')?.setAttribute('content', `${CONFIG.LOGO_ALT} logo`);
    document.getElementById('tw-image')?.setAttribute('content', CONFIG.OG_IMAGE);

    // Twitter handle
    document.getElementById('tw-site')?.setAttribute('content', CONFIG.TWITTER_HANDLE);
    // Also catch the older attribute-selector pattern for backwards compat
    document.querySelector('meta[name="twitter:site"]')?.setAttribute('content', CONFIG.TWITTER_HANDLE);

    // Favicon
    const faviconEl = document.getElementById('favicon') || document.querySelector('link[rel="icon"]');
    if (faviconEl) faviconEl.href = CONFIG.FAVICON_URL;

    // Auspicious bar
    const ausLink = Utils.qs('.auspicious-text') || document.getElementById('auspicious-link');
    if (ausLink) {
      ausLink.textContent = CONFIG.AUSPICIOUS_TEXT;
      ausLink.href        = CONFIG.AUSPICIOUS_URL;
      ausLink.setAttribute('aria-label', CONFIG.AUSPICIOUS_LABEL);
      ausLink.setAttribute('target', '_blank');
      ausLink.setAttribute('rel', 'noopener');
    }

    // Logo images (header + footer + loader)
    document.querySelectorAll('.logo__img, #loader-logo-img').forEach(img => {
      img.src = CONFIG.LOGO_IMG_URL;
      img.alt = CONFIG.LOGO_ALT;
    });

    // Wordmark text (the small "blog" label next to the logo)
    const wordmark = CONFIG.LOGO_WORDMARK || 'blog';
    document.querySelectorAll('.logo__sub').forEach(el => el.textContent = wordmark);
    const loaderSpan = document.querySelector('.loader__logo span');
    if (loaderSpan) loaderSpan.textContent = wordmark;

    // Logo link aria-label
    const logoLink = document.getElementById('logo-link');
    if (logoLink) logoLink.setAttribute('aria-label', `${CONFIG.BLOG_URL.replace('https://', '')} home`);

    // ── Navigation links (desktop + mobile) — driven by CONFIG.NAV_LINKS ──
    // Falls back gracefully if NAV_LINKS is not defined in an older config.
    const navLinks = (CONFIG.NAV_LINKS && CONFIG.NAV_LINKS.length)
      ? CONFIG.NAV_LINKS
      : [
          { label: 'Home',        href: '/'               },
          { label: 'Engineering', href: '/?tag=Engineering' },
          { label: 'Release',     href: '/?tag=Release'    },
          { label: 'Linux',       href: '/?tag=Linux'      },
          { label: 'News',        href: '/?tag=News'       },
        ];

    // Append Bookmarks link if feature is enabled
    const allNavLinks = CONFIG.BOOKMARKS_ENABLED
      ? [...navLinks, { label: '<i class="fa-solid fa-bookmark" aria-hidden="true"></i> Bookmarks', href: '/bookmarks', raw: true }]
      : navLinks;

    const navHtml = allNavLinks.map(({ label, href, raw }) => {
      const isExternal = href.startsWith('http') || href.startsWith('//');
      const ext = isExternal ? ' target="_blank" rel="noopener noreferrer"' : '';
      const labelHtml = raw ? label : Utils.escapeHtml(label);
      return `<a href="${href}"${ext}>${labelHtml}</a>`;
    }).join('');

    // PWA theme-color — sync with current theme
    const pwaTc = document.getElementById('pwa-theme-color');
    if (pwaTc) {
      pwaTc.content = AppState.theme === 'light' ? '#faf9f7' : '#161514';
    }

    const desktopNav = document.getElementById('desktop-nav');
    if (desktopNav) desktopNav.innerHTML = navHtml;

    const mobileNav = document.getElementById('mobile-nav');
    if (mobileNav) mobileNav.innerHTML = navHtml;

    // Footer social links
    const footerLinks = document.getElementById('footer-links');
    if (footerLinks) {
      footerLinks.innerHTML = CONFIG.SOCIAL_LINKS
        .map(s => `<a href="${s.url}" target="_blank" rel="noopener" aria-label="${s.label}"><i class="${s.icon}" aria-hidden="true"></i> <span>${s.label}</span></a>`)
        .join('');
    }

    // Current year
    document.querySelectorAll('[data-current-year]').forEach(el => el.textContent = new Date().getFullYear());

    // ── Cloudflare Web Analytics beacon ──────────────────────────
    // Privacy-safe, cookie-free. Injected once; idempotent on SPA re-renders.
    if (CONFIG.CF_WEB_ANALYTICS_TOKEN && !document.getElementById('cf-analytics')) {
      const cfScript = document.createElement('script');
      cfScript.id = 'cf-analytics';
      cfScript.defer = true;
      cfScript.src = 'https://static.cloudflareinsights.com/beacon.min.js';
      cfScript.dataset.cfBeacon = JSON.stringify({ token: CONFIG.CF_WEB_ANALYTICS_TOKEN });
      document.head.appendChild(cfScript);
    }

    // RSS feed discovery link
    if (CONFIG.RSS_ENABLED && CONFIG.RSS_URL) {
      if (!document.querySelector('link[type="application/rss+xml"]')) {
        const rssLink = document.createElement('link');
        rssLink.rel   = 'alternate';
        rssLink.type  = 'application/rss+xml';
        rssLink.title = `${CONFIG.SITE_TITLE} RSS Feed`;
        rssLink.href  = CONFIG.RSS_URL;
        document.head.appendChild(rssLink);
      }
    }

    // JSON-LD: Blog (homepage)
    const ldBlogs = document.getElementById('ld-blogs');
    if (ldBlogs) ldBlogs.textContent = JSON.stringify({
      "@context": "https://schema.org",
      "@type": "Blog",
      "name": CONFIG.SITE_TITLE,
      "url": `${CONFIG.BLOG_URL}/`,
      "description": CONFIG.SITE_DESCRIPTION,
      "publisher": {
        "@type": "Organization",
        "name": CONFIG.PUBLISHER_NAME,
        "url": CONFIG.PUBLISHER_URL,
        "logo": { "@type": "ImageObject", "url": CONFIG.PUBLISHER_LOGO }
      },
      "inLanguage": CONFIG.LANG || CONFIG.DATE_LOCALE || "en-US"
    });

    // JSON-LD: Organization
    const ldOrg = document.getElementById('ld-org');
    if (ldOrg) ldOrg.textContent = JSON.stringify({
      "@context": "https://schema.org",
      "@type": "Organization",
      "name": CONFIG.PUBLISHER_NAME,
      "url": CONFIG.PUBLISHER_URL,
      "logo": CONFIG.PUBLISHER_LOGO,
      "sameAs": CONFIG.SOCIAL_LINKS.map(s => s.url)
    });
  },

  renderHero(posts) {
    if (!posts.length) return;
    const p = posts[0];

    const words = p.title.split(' ');
    const last  = words.length > 1 ? words.pop() : '';
    const titleHtml = last
      ? `${Utils.escapeHtml(words.join(' '))} <em>${Utils.escapeHtml(last)}</em>`
      : `<em>${Utils.escapeHtml(p.title)}</em>`;

    const heroGrid = Utils.qs('.hero__grid');
    if (!heroGrid) return;

    heroGrid.innerHTML = `
      <div class="hero__featured" id="hero-featured-panel">
        <div class="hero__eyebrow">
          <span class="hero__eyebrow-dot"></span>
          ${CONFIG.HERO_EYEBROW}
        </div>
        <span class="hero__tag" id="hero-tag">${Utils.tagIcon(p.tag)} ${Utils.escapeHtml(p.tag)}</span>
        <h1 class="hero__title" id="hero-title">${titleHtml}</h1>
        <p class="hero__sub" id="hero-sub">${Utils.safeText(p.excerpt || CONFIG.HERO_SUB)}</p>
        <div class="meta" id="hero-meta">
          <span class="avatar">${Utils.escapeHtml(p.authorInitials)}</span>
          <span>${Utils.escapeHtml(p.author)}</span>
          <span class="meta-dot">·</span>
          <span>${Utils.fmtDateShort(p.date)}</span>
          <span class="meta-dot">·</span>
          <span><i class="fa-regular fa-clock"></i> ${p.readTime}</span>
          ${p.paywalled ? '<span class="members-badge"><i class="fa-solid fa-star"></i> Members</span>' : ''}
        </div>
        <button class="hero-link" id="hero-read-btn">Read post</button>
      </div>
      <aside class="hero__sidebar">
        <h3 class="sidebar__title">Also reading</h3>
        <ul class="sidebar__list" id="aside-list">
          <li class="loading-text">Loading…</li>
        </ul>
      </aside>`;

    Utils.qs('#hero-featured-panel').addEventListener('click', () => Router.go(p.slug));
    Utils.qs('#hero-read-btn').addEventListener('click', e => { e.stopPropagation(); Router.go(p.slug); });

    const { perPage } = AppState.pagination;
    // Skip the hero post (index 0) and all posts visible in the main grid (indices 1..perPage-1).
    // Sidebar shows the next batch so nothing duplicates the index view.
    const sidebarStart = perPage;
    const _hsc = CONFIG.HERO_SIDEBAR_COUNT || 4; const items = posts.slice(sidebarStart, sidebarStart + _hsc);
    const asideList = Utils.qs('#aside-list');
    asideList.innerHTML = items.length
      ? items.map(item => `
          <li>
            <button class="sidebar__link" data-slug="${Utils.escapeHtml(item.slug)}">
              ${Utils.tagIcon(item.tag)} ${Utils.escapeHtml(item.title)}
            </button>
            <span class="sidebar__date">
              <i class="fa-regular fa-calendar"></i> ${Utils.fmtDateShort(item.date)}
              <span class="meta-dot">·</span>
              <i class="fa-regular fa-clock"></i> ${Utils.escapeHtml(item.readTime)}
            </span>
          </li>`).join('')
      : '<li class="loading-text">No more posts</li>';

    asideList.querySelectorAll('.sidebar__link[data-slug]').forEach(btn => {
      btn.addEventListener('click', e => { e.stopPropagation(); Router.go(btn.dataset.slug); });
    });
  },

  renderPosts(posts, showFeatured = false) {
    const grid = Utils.qs('#posts-grid');
    if (!posts.length) {
      grid.innerHTML = `<div class="empty-state"><i class="fa-solid fa-inbox empty-icon"></i><h3>No posts found</h3><p>Try a different topic or check back soon.</p></div>`;
      return;
    }
    // ── Search term highlighting helper ──────────────────────────
    const _hlSearch = (text) => {
      if (!AppState.search || CONFIG.SEARCH_HIGHLIGHT === false) return Utils.escapeHtml(text);
      const q = AppState.search.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
      return Utils.escapeHtml(text).replace(
        new RegExp(`(${q})`, 'gi'),
        '<mark class="search-mark">$1</mark>'
      );
    };

    grid.innerHTML = posts.map((p, i) => {
      const isFeat = showFeatured && i === 0;
      const visual = p.cover
        ? `<img src="${Utils.escapeHtml(p.cover)}" alt="${Utils.escapeHtml(p.title)}" class="card__cover-img" loading="lazy">`
        : `<i class="fa-solid fa-file-lines card__icon" aria-hidden="true"></i>`;
      const showRT = CONFIG.CARD_SHOW_READ_TIME !== false;
      const isBookmarked = CONFIG.BOOKMARKS_ENABLED && localStorage.getItem(_key('bm:' + p.slug)) === '1';
      // ── Freshness badge ─────────────────────────────────────────
      const _postAge = p.date ? Math.floor((Date.now() - new Date(p.date + 'T00:00:00')) / 86400000) : 999;
      const _newDays = CONFIG.NEW_POST_DAYS || 7;
      const _recentDays = CONFIG.RECENT_POST_DAYS || 30;
      const _freshBadge = _newDays > 0 && _postAge <= _newDays
        ? '<span class="freshness-badge freshness-badge--new">New</span>'
        : (_recentDays > 0 && _postAge <= _recentDays
          ? '<span class="freshness-badge freshness-badge--recent">Recent</span>'
          : '');
      return `<article class="card ${isFeat ? 'featured' : ''}" role="listitem" data-idx="${i}">
        <div class="card__visual">
          ${visual}
          <button class="card__copy-link" data-url="${Utils.escapeHtml(`${CONFIG.BLOG_URL}/post/${p.slug}`)}" aria-label="Copy link" title="Copy link"><i class="fa-solid fa-link"></i></button>
        </div>
        <div class="card__content">
          <span class="card__tag" data-tag="${Utils.escapeHtml(p.tag)}"><i class="${TAG_ICONS[p.tag] || TAG_ICONS.Post}"></i> ${Utils.escapeHtml(p.tag)}</span>
          <h2 class="card__title">${_freshBadge}${_hlSearch(p.title)}</h2>
          <p class="card__excerpt">${_hlSearch(p.excerpt)}</p>
          <div class="card__footer">
            <span class="card__author"><i class="fa-solid fa-user-pen"></i> ${Utils.escapeHtml(p.author)}</span>
            <span class="card__meta">
              <i class="fa-regular fa-calendar"></i> ${Utils.fmtDateShort(p.date)}
              ${showRT ? `<span class="meta-dot">·</span><i class="fa-regular fa-clock"></i> ${Utils.escapeHtml(p.readTime)}` : ''}
              ${p.paywalled ? '<span class="members-badge"><i class="fa-solid fa-star"></i></span>' : ''}
              ${CONFIG.VIEW_COUNT_ENABLED !== false ? `<span class="meta-dot">·</span><span class="view-count" title="Views"><i class="fa-regular fa-eye"></i> ${ViewCounter.fmt(ViewCounter.get(p.slug))}</span>` : ''}
            </span>
            ${CONFIG.BOOKMARKS_ENABLED ? `<button class="card__bookmark${isBookmarked ? ' bookmarked' : ''}" data-bm="${Utils.escapeHtml(p.slug)}" aria-label="${isBookmarked ? 'Remove bookmark' : 'Bookmark'}" title="${isBookmarked ? 'Remove bookmark' : 'Save for later'}"><i class="fa-${isBookmarked ? 'solid' : 'regular'} fa-bookmark"></i></button>` : ''}
          </div>
        </div>
      </article>`;
    }).join('');

    grid.querySelectorAll('.card').forEach(card => {
      const idx = parseInt(card.dataset.idx);
      card.setAttribute('tabindex', '0');
      card.setAttribute('aria-label', `Read: ${posts[idx].title}`);
      card.addEventListener('click', e => {
        const tagChip = e.target.closest('.card__tag');
        if (tagChip) {
          e.stopPropagation();
          Router.setQuery({ tag: posts[idx].tag, page: 1 });
          return;
        }
        const copyBtn = e.target.closest('.card__copy-link');
        if (copyBtn) {
          e.stopPropagation();
          UI.copyToClipboard(copyBtn.dataset.url).then(() =>
            UI.showToast('<i class="fa-solid fa-check"></i> Link copied')
          );
          return;
        }
        const bmBtn = e.target.closest('.card__bookmark');
        if (bmBtn) {
          e.stopPropagation();
          const slug = bmBtn.dataset.bm;
          const isBm = localStorage.getItem(_key('bm:' + slug)) === '1';
          const next = !isBm;
          localStorage.setItem(_key('bm:' + slug), next ? '1' : '0');
          bmBtn.classList.toggle('bookmarked', next);
          bmBtn.setAttribute('aria-label', next ? 'Remove bookmark' : 'Bookmark');
          bmBtn.setAttribute('title', next ? 'Remove bookmark' : 'Save for later');
          bmBtn.innerHTML = `<i class="fa-${next ? 'solid' : 'regular'} fa-bookmark"></i>`;
          UI.showToast(next
            ? '<i class="fa-solid fa-bookmark"></i> Saved to bookmarks'
            : '<i class="fa-regular fa-bookmark"></i> Removed from bookmarks');
          return;
        }
        Router.go(posts[idx].slug);
      });
      card.addEventListener('keydown', e => {
        if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); Router.go(posts[idx].slug); }
      });
    });
  },

  renderPagination(total, perPage, currentPage) {
    let container = Utils.qs('#pagination-container');
    if (!container) {
      container = document.createElement('div');
      container.id = 'pagination-container';
      const grid = Utils.qs('#posts-grid');
      if (grid && grid.parentNode) grid.parentNode.insertBefore(container, grid.nextSibling);
    }
    const totalPages = Math.ceil(total / perPage);
    if (totalPages <= 1) { container.innerHTML = ''; return; }

    const pageSet = new Set([1, totalPages]);
    for (let i = Math.max(1, currentPage - 1); i <= Math.min(totalPages, currentPage + 1); i++) pageSet.add(i);
    const sorted = [...pageSet].sort((a, b) => a - b);

    const items = [];
    let prev = 0;
    for (const p of sorted) {
      if (p - prev > 1) items.push('…');
      items.push(p);
      prev = p;
    }

    let html = `<nav class="pagination" aria-label="Post pages">`;
    html += `<button class="pag-btn${currentPage === 1 ? ' disabled' : ''}"
              data-page="${currentPage - 1}"
              aria-label="Previous page"
              ${currentPage === 1 ? 'disabled' : ''}>← Prev</button>`;

    for (const item of items) {
      if (item === '…') {
        html += `<span class="pag-ellipsis">…</span>`;
      } else if (item === currentPage) {
        html += `<button class="pag-btn active" disabled aria-current="page">${item}</button>`;
      } else {
        html += `<button class="pag-btn" data-page="${item}" aria-label="Go to page ${item}">${item}</button>`;
      }
    }

    html += `<button class="pag-btn${currentPage === totalPages ? ' disabled' : ''}"
              data-page="${currentPage + 1}"
              aria-label="Next page"
              ${currentPage === totalPages ? 'disabled' : ''}>Next →</button>`;
    html += `</nav>`;
    container.innerHTML = html;

    container.querySelectorAll('.pag-btn:not(.disabled):not([disabled])').forEach(btn => {
      btn.addEventListener('click', () => {
        const newPage = parseInt(btn.dataset.page);
        if (!newPage) return;
        Router.setQuery({ tag: AppState.filter === 'all' ? null : AppState.filter, page: newPage });
        Utils.qs('#posts-grid')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      });
    });
  },

  renderPost(post) {
    const app = Utils.qs('#post-article');
    const html = Utils.safeMarkdown(post.body || '');
    const paywalled = post.paywalled;
    const date = Utils.fmtDateShort(post.date);

    // ── Update all meta / SEO for this post ───────────────────
    const postUrl  = `${CONFIG.BLOG_URL}/post/${post.slug}`;
    const ogImg    = post.cover || CONFIG.OG_IMAGE;

    document.title = `${post.title} — ${CONFIG.SITE_TITLE}`;
    document.getElementById('canonical-url')?.setAttribute('href', postUrl);
    document.getElementById('meta-desc')?.setAttribute('content', post.excerpt);
    document.getElementById('og-type')?.setAttribute('content', 'article');
    ['og-title', 'tw-title'].forEach(id => Utils.qs(`#${id}`)?.setAttribute('content', post.title));
    ['og-desc',  'tw-desc' ].forEach(id => Utils.qs(`#${id}`)?.setAttribute('content', post.excerpt));
    document.getElementById('og-url')?.setAttribute('content', postUrl);
    document.getElementById('og-image')?.setAttribute('content', ogImg);
    document.getElementById('tw-image')?.setAttribute('content', ogImg);

    // JSON-LD: BlogPosting
    const ldBlogs = document.getElementById('ld-blogs');
    if (ldBlogs) ldBlogs.textContent = JSON.stringify({
      "@context": "https://schema.org", "@type": "BlogPosting",
      "headline": post.title, "description": post.excerpt, "datePublished": post.date,
      ...(post.cover ? { "image": post.cover } : {}),
      "author": { "@type": "Person", "name": post.author },
      "publisher": {
        "@type": "Organization",
        "name": CONFIG.PUBLISHER_NAME,
        "url": CONFIG.PUBLISHER_URL,
        "logo": { "@type": "ImageObject", "url": CONFIG.PUBLISHER_LOGO }
      },
      "mainEntityOfPage": { "@type": "WebPage", "@id": postUrl },
      "url": postUrl, "keywords": post.tag, "inLanguage": CONFIG.LANG || CONFIG.DATE_LOCALE || "en-US"
    });

    // JSON-LD: BreadcrumbList
    const ldOrg = document.getElementById('ld-org');
    if (ldOrg) ldOrg.textContent = JSON.stringify({
      "@context": "https://schema.org", "@type": "BreadcrumbList",
      "itemListElement": [
        { "@type": "ListItem", "position": 1, "name": "Home",     "item": `${CONFIG.BLOG_URL}/` },
        { "@type": "ListItem", "position": 2, "name": post.tag,   "item": `${CONFIG.BLOG_URL}/?tag=${post.tag}` },
        { "@type": "ListItem", "position": 3, "name": post.title, "item": postUrl }
      ]
    });

    // ── Paywall ───────────────────────────────────────────────
    let content = '';
    if (paywalled && !AppState.isMember) {
      const div = document.createElement('div');
      div.innerHTML = html;
      const blocks = [...div.children];
      // Always show TOC/h1 blocks; count only content blocks toward the preview limit
      const alwaysShow = el => el.matches('nav.toc, h1');
      const contentBlocks = blocks.filter(el => !alwaysShow(el));
      const freeContent   = contentBlocks.slice(0, CONFIG.PAYWALL_PREVIEW_BLOCKS || 12);
      const tocBlocks     = blocks.filter(el => alwaysShow(el));
      const free  = [...tocBlocks, ...freeContent].map(n => n.outerHTML).join('');
      content = `<div class="paywall-wrap" data-blog-url="${CONFIG.BLOG_URL}"><div class="post-body paywall-fade">${free || '<p>' + (post.excerpt || '') + '</p>'}</div></div>
         <div class="paywall-gate"><div class="paywall-card">
           <i class="fa-solid fa-lock paywall-icon"></i>
           <h3>${Utils.escapeHtml(CONFIG.PAYWALL_HEADING || 'Members only')}</h3>
           <p>${Utils.escapeHtml(CONFIG.PAYWALL_DESCRIPTION || 'This post is for members. Purchase a membership to unlock all gated posts.')}</p>
           <div class="paywall-actions">
             <a class="btn primary" href="${CONFIG.MEMBERSHIP_URL}" target="_blank" rel="noopener">
               <i class="fa-solid fa-cart-shopping"></i> Get Access — ${CONFIG.MEMBERSHIP_PRICE}
             </a>
             <button class="btn" id="back-btn"><i class="fa-solid fa-arrow-left"></i> Back to posts</button>
           </div>
           <div class="paywall-key-wrap">
             <p class="paywall-key-label">${Utils.escapeHtml(CONFIG.PAYWALL_KEY_LABEL || 'Already a member? Enter your license key:')}</p>
             <div class="paywall-key-row">
               <input type="text" id="license-input" class="paywall-key-input" placeholder="${Utils.escapeHtml(CONFIG.PAYWALL_KEY_PLACEHOLDER || 'XXXXXXXX-XXXXXXXX-XXXXXXXX-XXXXXXXX')}" spellcheck="false" autocomplete="off">
               <button class="btn primary" id="unlock-btn"><i class="fa-solid fa-unlock"></i> Unlock</button>
             </div>
             <p class="paywall-key-status" id="key-status" aria-live="polite"></p>
           </div>
         </div></div>`;
    } else {
      content = `<div class="post-body">${html}</div>`;
    }

    // Increment view counter BEFORE render so the count shown in the header is current
    ViewCounter.increment(post.slug);
    RecentlyViewed.add(post.slug);

    const liked    = localStorage.getItem(_key('liked:' + post.slug)) === '1';
    const liked_bm = CONFIG.BOOKMARKS_ENABLED && localStorage.getItem(_key('bm:' + post.slug)) === '1';

    app.innerHTML = `
      <header class="post-header">
        <button class="post-back" id="post-back-btn"><i class="fa-solid fa-arrow-left"></i> Back</button>
        <span class="post-tag">${Utils.tagIcon(post.tag)} ${Utils.escapeHtml(post.tag)}</span>
        <h1 class="post-title">${Utils.escapeHtml(post.title)}</h1>
        ${(() => {
          if (!post.excerpt) return '';
          // Suppress header excerpt if the post body opens with the same text
          const bodyStart = (post.body || '').replace(/^#{1,6}\s+[^\n]+\n+/, '')
            .replace(/[*_`#>\[\]]/g, '').trim().substring(0, 80).toLowerCase();
          const excStart  = post.excerpt.replace(/[*_`#>\[\]]/g, '').trim().substring(0, 80).toLowerCase();
          if (bodyStart && excStart && bodyStart.startsWith(excStart.substring(0, 60))) return '';
          return `<p class="post-excerpt">${Utils.safeText(post.excerpt)}</p>`;
        })()}
        <div class="post-meta">
          <span class="avatar">${Utils.escapeHtml(post.authorInitials)}</span>
          <div class="meta-info">
            <div class="meta-name">${Utils.escapeHtml(post.author)}</div>
            <div class="meta-details">
              <span title="${Utils.escapeHtml(RelDate.fmt(post.date))}"><i class="fa-regular fa-calendar"></i> ${date}</span>
              <span class="meta-dot">·</span>
              <span><i class="fa-regular fa-clock"></i> ${Utils.escapeHtml(post.readTime)}</span>
              ${CONFIG.SHOW_WORD_COUNT !== false && post.body ? `<span class="meta-dot">·</span><span title="Word count"><i class="fa-solid fa-align-left"></i> ${WordCount.fmt(WordCount.count(post.body))}</span>` : ''}
              ${CONFIG.VIEW_COUNT_ENABLED !== false ? `<span class="meta-dot">·</span><span class="view-count" title="Views"><i class="fa-regular fa-eye"></i> ${ViewCounter.fmt(ViewCounter.get(post.slug))}</span>` : ''}
              ${paywalled ? '<span class="meta-dot">·</span><span class="members-badge"><i class="fa-solid fa-star"></i> Members</span>' : ''}
            </div>
          </div>
          <div class="meta-actions">
            ${CONFIG.FONT_SIZE_CONTROLS !== false ? `<div class="font-size-ctrl" aria-label="Text size">
              <button class="btn btn--icon-sm" id="font-dec" title="Smaller text" aria-label="Decrease font size"><span>A−</span></button>
              <button class="btn btn--icon-sm" id="font-rst" title="Reset text size" aria-label="Reset font size"><span>A</span></button>
              <button class="btn btn--icon-sm" id="font-inc" title="Larger text" aria-label="Increase font size"><span>A+</span></button>
            </div>` : ''}
            ${CONFIG.BOOKMARKS_ENABLED ? `<button class="btn ${liked_bm ? 'bookmarked' : ''}" id="post-bookmark-btn" aria-label="Bookmark"><i class="fa-${liked_bm ? 'solid' : 'regular'} fa-bookmark"></i> ${liked_bm ? 'Saved' : 'Save'}</button>` : ''}
            ${!(paywalled && !AppState.isMember) ? '<button class="btn" id="print-btn"><i class="fa-solid fa-print"></i> Print</button>' : ''}
            <button class="btn" id="share-btn"><i class="fa-solid fa-share-nodes"></i> Share</button>
          </div>
        </div>
      </header>
      ${post.cover
        ? `<div class="post-cover post-cover--img"><img src="${Utils.escapeHtml(post.cover)}" alt="${Utils.escapeHtml(post.title)}" class="post-cover__img"></div>`
        : ''
      }
      ${content}
      ${(() => {
        const links = [
          post.authorLinkedin ? `<a href="${Utils.escapeHtml(post.authorLinkedin)}" target="_blank" rel="noopener" class="author-card__link" aria-label="LinkedIn"><i class="fa-brands fa-linkedin"></i> LinkedIn</a>` : '',
          post.authorGithub   ? `<a href="${Utils.escapeHtml(post.authorGithub)}"   target="_blank" rel="noopener" class="author-card__link" aria-label="GitHub"><i class="fa-brands fa-github"></i> GitHub</a>` : '',
          post.authorWebsite  ? `<a href="${Utils.escapeHtml(post.authorWebsite)}"  target="_blank" rel="noopener" class="author-card__link" aria-label="Website"><i class="fa-solid fa-globe"></i> Website</a>` : '',
        ].filter(Boolean).join('');
        return `<div class="author-card">
          <span class="author-card__avatar">${Utils.escapeHtml(post.authorInitials)}</span>
          <div class="author-card__body">
            <div class="author-card__label">Written by</div>
            <div class="author-card__name">${Utils.escapeHtml(post.author)}</div>
            ${post.authorRole ? `<div class="author-card__role">${Utils.safeText(post.authorRole)}</div>` : ''}
            ${post.authorBio  ? `<p class="author-card__bio">${Utils.safeText(post.authorBio)}</p>` : ''}
            ${links ? `<div class="author-card__links">${links}</div>` : ''}
          </div>
        </div>`;
      })()}
      <footer class="post-footer">
        <div class="post-tags">
          <button class="tag-chip" data-back-tag="${Utils.escapeHtml(post.tag)}" title="Browse all ${Utils.escapeHtml(post.tag)} posts">${Utils.tagIcon(post.tag)} More ${Utils.escapeHtml(post.tag)}</button>
          <button class="tag-chip" id="all-posts-btn"><i class="fa-solid fa-grip"></i> All Posts</button>
        </div>
        <div class="meta-actions">
          <button class="btn like ${liked ? 'reacted' : ''}" id="like-btn">
            <i class="fa-${liked ? 'solid' : 'regular'} fa-heart"></i> ${liked ? 'Liked' : 'Like'}
          </button>
          <button class="btn" id="footer-copy-link-btn" aria-label="Copy link"><i class="fa-solid fa-link"></i> Copy link</button>
          <button class="btn" id="footer-share-btn"><i class="fa-solid fa-share-nodes"></i> Share</button>
          ${!(paywalled && !AppState.isMember) ? '<button class="btn" id="footer-print-btn"><i class="fa-solid fa-print"></i> Print</button>' : ''}
        </div>
        <div class="post-nav" id="post-nav-btns"></div>
      </footer>
      <div id="post-series-strip"></div>
      <div id="post-related"></div>
      <div id="post-newsletter"></div>
      ${CONFIG.GISCUS_ENABLED && CONFIG.GISCUS_REPO && !(paywalled && !AppState.isMember) ? `
      <div id="post-comments" class="post-comments">
        <div class="section-header">
          <h2 class="section-header__title"><i class="fa-solid fa-comments" aria-hidden="true"></i> Discussion</h2>
          <div class="section-header__line"></div>
        </div>
        <div class="giscus"></div>
      </div>` : ''}`;

    // ── Adaptive paywall fade ─────────────────────────────────
    // After the DOM is painted, measure the preview's natural height.
    // • Short preview  (<= threshold): show all content fully — no clip, no fade.
    //   This prevents a jarring hard cut on posts that only have a paragraph or two of free content.
    // • Tall preview   (>  threshold): cap to FADE_CAP px and apply the gradient mask
    //   so the fade always lands visibly within the rendered text, never below it.
    const fadeEl = app.querySelector('.paywall-fade');
    if (fadeEl) {
      const FADE_THRESHOLD = 380; // px — shorter than this → show in full
      const FADE_CAP       = 460; // px — cap height when clipping
      requestAnimationFrame(() => {
        // scrollHeight gives the full rendered height even when overflow:hidden
        const naturalH = fadeEl.scrollHeight;
        if (naturalH > FADE_THRESHOLD) {
          fadeEl.style.maxHeight = FADE_CAP + 'px';
          fadeEl.classList.add('paywall-fade--clipped');
        } else {
          // Content is short — reveal it fully so the gate appears directly below
          fadeEl.style.maxHeight = naturalH + 'px';
          // No mask needed; gate follows immediately
        }
      });
    }

    // ── Wire up all post interactions ─────────────────────────
    app.querySelector('#post-back-btn')?.addEventListener('click', () => Router.back());
    app.querySelector('#print-btn')?.addEventListener('click', () => window.print());
    app.querySelector('#all-posts-btn')?.addEventListener('click', () => Router.back());
    app.querySelector('[data-back-tag]')?.addEventListener('click', function() {
      Router.back(this.dataset.backTag);
    });
    app.querySelector('#like-btn')?.addEventListener('click', function () {
      const is = this.classList.toggle('reacted');
      this.innerHTML = `<i class="fa-${is ? 'solid' : 'regular'} fa-heart"></i> ${is ? 'Liked' : 'Like'}`;
      localStorage.setItem(_key('liked:' + post.slug), is ? '1' : '0');
    });

    // Prev / Next navigation
    const navEl = app.querySelector('#post-nav-btns');
    if (navEl && AppState.posts.length) {
      const idx  = AppState.posts.findIndex(p => p.slug === post.slug);
      const prev = idx < AppState.posts.length - 1 ? AppState.posts[idx + 1] : null;
      const next = idx > 0 ? AppState.posts[idx - 1] : null;
      navEl.innerHTML = `
        ${prev ? `<button class="post-nav-btn" id="nav-prev">
           <div class="nav-label"><i class="fa-solid fa-arrow-left"></i> Older</div>
           <div class="nav-title">${Utils.escapeHtml(prev.title)}</div>
         </button>` : '<div class="post-nav-btn post-nav-btn--empty"></div>'}
        ${next ? `<button class="post-nav-btn post-nav-btn--right" id="nav-next">
           <div class="nav-label">Newer <i class="fa-solid fa-arrow-right"></i></div>
           <div class="nav-title">${Utils.escapeHtml(next.title)}</div>
         </button>` : '<div class="post-nav-btn post-nav-btn--right post-nav-btn--empty"></div>'}`;
      navEl.querySelector('#nav-prev')?.addEventListener('click', () => Router.go(prev.slug));
      navEl.querySelector('#nav-next')?.addEventListener('click', () => Router.go(next.slug));
    }

    // ── Font size controls ────────────────────────────────────────
    if (CONFIG.FONT_SIZE_CONTROLS !== false) {
      const postBody = app.querySelector('.post-body');
      const FS_SIZES = [14, 16, 18, 20, 22]; // px options
      const FS_DEFAULT = 16;
      let fsCurrent = parseInt(localStorage.getItem(_key('font_size')) || FS_DEFAULT);
      const applyFontSize = (sz) => {
        fsCurrent = Math.max(FS_SIZES[0], Math.min(FS_SIZES[FS_SIZES.length-1], sz));
        if (postBody) postBody.style.fontSize = fsCurrent + 'px';
        localStorage.setItem(_key('font_size'), fsCurrent);
        app.querySelector('#font-dec').disabled = fsCurrent <= FS_SIZES[0];
        app.querySelector('#font-inc').disabled = fsCurrent >= FS_SIZES[FS_SIZES.length-1];
      };
      applyFontSize(fsCurrent);
      app.querySelector('#font-dec')?.addEventListener('click', () => applyFontSize(fsCurrent - 2));
      app.querySelector('#font-rst')?.addEventListener('click', () => applyFontSize(FS_DEFAULT));
      app.querySelector('#font-inc')?.addEventListener('click', () => applyFontSize(fsCurrent + 2));
    }

    app.querySelector('#share-btn')?.addEventListener('click', () => UI.share(post));
    app.querySelector('#footer-share-btn')?.addEventListener('click', () => UI.share(post));
    app.querySelector('#footer-copy-link-btn')?.addEventListener('click', () => {
      UI.copyToClipboard(location.href).then(() =>
        UI.showToast('<i class="fa-solid fa-check"></i> Link copied')
      );
    });
    app.querySelector('#footer-print-btn')?.addEventListener('click', () => window.print());

    app.querySelector('#back-btn')?.addEventListener('click', () => Router.back());

    // ── Bookmark toggle on post page ─────────────────────────────
    app.querySelector('#post-bookmark-btn')?.addEventListener('click', function() {
      const isBm = localStorage.getItem(_key('bm:' + post.slug)) === '1';
      const next = !isBm;
      localStorage.setItem(_key('bm:' + post.slug), next ? '1' : '0');
      this.classList.toggle('bookmarked', next);
      this.innerHTML = `<i class="fa-${next ? 'solid' : 'regular'} fa-bookmark"></i> ${next ? 'Saved' : 'Save'}`;
      UI.showToast(next
        ? '<i class="fa-solid fa-bookmark"></i> Saved to bookmarks'
        : '<i class="fa-regular fa-bookmark"></i> Removed from bookmarks');
    });

    // ── Series navigation strip ───────────────────────────────────
    if (CONFIG.SERIES_ENABLED && post.series && AppState.posts.length) {
      const seriesPosts = AppState.posts
        .filter(p => p.series && p.series === post.series)
        .sort((a, b) => new Date(a.date) - new Date(b.date));
      if (seriesPosts.length > 1) {
        const seriesEl = app.querySelector('#post-series-strip');
        const currentIdx = seriesPosts.findIndex(p => p.slug === post.slug);
        seriesEl.innerHTML = `
          <div class="series-strip">
            <div class="series-strip__header">
              <i class="fa-solid fa-layer-group" aria-hidden="true"></i>
              <span>Part of a series: <strong>${Utils.escapeHtml(post.series)}</strong></span>
              <span class="series-strip__count">${currentIdx + 1} / ${seriesPosts.length}</span>
            </div>
            <ol class="series-strip__list">
              ${seriesPosts.map((sp, si) => `
                <li class="series-strip__item${sp.slug === post.slug ? ' active' : ''}">
                  <button class="series-strip__btn" data-slug="${Utils.escapeHtml(sp.slug)}" ${sp.slug === post.slug ? 'disabled' : ''}>
                    <span class="series-strip__num">${si + 1}</span>
                    <span class="series-strip__title">${Utils.escapeHtml(sp.title)}</span>
                    ${sp.slug === post.slug ? '<span class="series-strip__badge">Reading</span>' : ''}
                  </button>
                </li>`).join('')}
            </ol>
          </div>`;
        seriesEl.querySelectorAll('.series-strip__btn:not([disabled])').forEach(btn => {
          btn.addEventListener('click', () => Router.go(btn.dataset.slug));
        });
      }
    }

    // ── Related posts ─────────────────────────────────────────────
    const relCount = parseInt(CONFIG.RELATED_POSTS_COUNT) || 0;
    if (relCount > 0 && AppState.posts.length > 1) {
      const related = AppState.posts
        .filter(p => p.slug !== post.slug)
        .sort((a, b) => {
          const aScore = (a.tag === post.tag ? 2 : 0);
          const bScore = (b.tag === post.tag ? 2 : 0);
          return bScore - aScore || new Date(b.date) - new Date(a.date);
        })
        .slice(0, relCount);
      const relEl = app.querySelector('#post-related');
      if (related.length) {
        relEl.innerHTML = `
          <section class="related-posts">
            <div class="section-header">
              <h2 class="section-header__title">Keep reading</h2>
              <div class="section-header__line"></div>
            </div>
            <div class="related-posts__grid">
              ${related.map(rp => {
                const visual = rp.cover
                  ? `<img src="${Utils.escapeHtml(rp.cover)}" alt="${Utils.escapeHtml(rp.title)}" loading="lazy">`
                  : `<i class="fa-solid fa-file-lines" aria-hidden="true"></i>`;
                return `<button class="related-card" data-slug="${Utils.escapeHtml(rp.slug)}">
                  <div class="related-card__visual">${visual}</div>
                  <div class="related-card__body">
                    <span class="related-card__tag">${Utils.tagIcon(rp.tag)} ${Utils.escapeHtml(rp.tag)}</span>
                    <h3 class="related-card__title">${Utils.escapeHtml(rp.title)}</h3>
                    <span class="related-card__meta"><i class="fa-regular fa-clock"></i> ${Utils.escapeHtml(rp.readTime)}</span>
                  </div>
                </button>`;
              }).join('')}
            </div>
          </section>`;
        relEl.querySelectorAll('.related-card').forEach(btn => {
          btn.addEventListener('click', () => Router.go(btn.dataset.slug));
        });
      }
    }

    // ── Newsletter signup ─────────────────────────────────────────
    if (CONFIG.NEWSLETTER_ENABLED && !AppState.isMember) {
      const nlEl = app.querySelector('#post-newsletter');
      nlEl.innerHTML = `
        <div class="newsletter-block">
          <div class="newsletter-block__icon"><i class="fa-solid fa-envelope-open-text" aria-hidden="true"></i></div>
          <h3 class="newsletter-block__headline">${Utils.escapeHtml(CONFIG.NEWSLETTER_HEADLINE || 'Stay in the loop')}</h3>
          <p class="newsletter-block__desc">${Utils.escapeHtml(CONFIG.NEWSLETTER_DESCRIPTION || '')}</p>
          <div class="newsletter-block__form" id="nl-form">
            <input type="email" class="newsletter-block__input" id="nl-email"
              placeholder="${Utils.escapeHtml(CONFIG.NEWSLETTER_PLACEHOLDER || 'you@example.com')}"
              autocomplete="email" required>
            <button class="btn primary newsletter-block__btn" id="nl-submit">
              <i class="fa-solid fa-paper-plane"></i> ${Utils.escapeHtml(CONFIG.NEWSLETTER_CTA || 'Subscribe')}
            </button>
          </div>
          <p class="newsletter-block__status" id="nl-status" aria-live="polite"></p>
        </div>`;

      const nlForm   = nlEl.querySelector('#nl-form');
      const nlEmail  = nlEl.querySelector('#nl-email');
      const nlSubmit = nlEl.querySelector('#nl-submit');
      const nlStatus = nlEl.querySelector('#nl-status');

      const doSubscribe = async () => {
        const email = nlEmail.value.trim();
        if (!email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
          nlStatus.textContent = 'Please enter a valid email address.';
          nlStatus.className   = 'newsletter-block__status newsletter-block__status--error';
          return;
        }
        nlSubmit.disabled = true;
        nlSubmit.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Subscribing…';
        nlStatus.textContent = '';

        if (CONFIG.NEWSLETTER_ACTION) {
          try {
            const fd = new FormData();
            fd.append('email', email);
            await fetch(CONFIG.NEWSLETTER_ACTION, { method: 'POST', body: fd, mode: 'no-cors' });
          } catch { /* no-cors swallows errors; assume success */ }
        }

        nlStatus.textContent = CONFIG.NEWSLETTER_SUCCESS || "You're subscribed!";
        nlStatus.className   = 'newsletter-block__status newsletter-block__status--ok';
        nlForm.style.display = 'none';
        sessionStorage.setItem(_key('nl_done'), '1');
      };

      if (sessionStorage.getItem(_key('nl_done')) === '1') {
        nlForm.style.display = 'none';
        nlStatus.textContent = CONFIG.NEWSLETTER_SUCCESS || "You're subscribed!";
        nlStatus.className   = 'newsletter-block__status newsletter-block__status--ok';
      } else {
        nlSubmit.addEventListener('click', doSubscribe);
        nlEmail.addEventListener('keydown', e => { if (e.key === 'Enter') doSubscribe(); });
      }
    }

    // ── Giscus comments ───────────────────────────────────────────
    if (CONFIG.GISCUS_ENABLED && CONFIG.GISCUS_REPO && !(paywalled && !AppState.isMember)) {
      // Resolve theme: explicit config value, or follow the blog's own toggle
      const giscusTheme = CONFIG.GISCUS_THEME ||
        (AppState.theme === 'dark' ? 'dark_dimmed' : 'light');

      // Remove any previous Giscus iframe so it re-mounts cleanly on navigation
      const prevScript = document.getElementById('giscus-script');
      if (prevScript) prevScript.remove();
      document.querySelector('iframe.giscus-frame')?.remove();

      const gs = document.createElement('script');
      gs.id = 'giscus-script';
      gs.src = 'https://giscus.app/client.js';
      gs.async = true;
      gs.crossOrigin = 'anonymous';
      gs.dataset.repo           = CONFIG.GISCUS_REPO;
      gs.dataset.repoId         = CONFIG.GISCUS_REPO_ID;
      gs.dataset.category       = CONFIG.GISCUS_CATEGORY || 'General';
      gs.dataset.categoryId     = CONFIG.GISCUS_CATEGORY_ID;
      gs.dataset.mapping        = CONFIG.GISCUS_MAPPING || 'pathname';
      gs.dataset.strict         = '0';
      gs.dataset.reactionsEnabled = '1';
      gs.dataset.emitMetadata   = '0';
      gs.dataset.inputPosition  = 'top';
      gs.dataset.theme          = giscusTheme;
      gs.dataset.lang           = (CONFIG.LANG || 'en').split('-')[0];
      gs.dataset.loading        = 'lazy';

      // Inject into the .giscus container rendered in the post HTML
      const giscusContainer = app.querySelector('.giscus');
      if (giscusContainer) giscusContainer.appendChild(gs);
    }

    // ── Lemon Squeezy license key verification ───────────────────
    const unlockBtn   = app.querySelector('#unlock-btn');
    const licenseInput = app.querySelector('#license-input');
    const keyStatus   = app.querySelector('#key-status');

    if (unlockBtn && licenseInput) {
      const setStatus = (msg, isError) => {
        if (!keyStatus) return;
        keyStatus.textContent = msg;
        keyStatus.className = 'paywall-key-status ' + (isError ? 'paywall-key-status--error' : 'paywall-key-status--ok');
      };

      const doVerify = async () => {
        const key = licenseInput.value.trim();
        if (!key) { setStatus('Please enter your license key.', true); return; }

        unlockBtn.disabled = true;
        unlockBtn.innerHTML = '<i class="fa-solid fa-spinner fa-spin"></i> Checking…';
        setStatus('', false);

        try {
          // Lemon Squeezy license validate — CORS-enabled, no server needed
          const lsParams = { license_key: key };
          if (CONFIG.LEMONSQUEEZY_PRODUCT) lsParams.product_id = CONFIG.LEMONSQUEEZY_PRODUCT;
          const res = await fetch('https://api.lemonsqueezy.com/v1/licenses/validate', {
            method: 'POST',
            headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
            body: new URLSearchParams(lsParams)
          });
          const data = await res.json();

          if (data.valid) {
            localStorage.setItem(_key('member'), '1');
            await LicenseCrypto.store(key); // stores SHA-256 hash only — raw key is never persisted
            AppState.isMember = true;
            // Clear the stripped cache so the full body is re-fetched
            delete AppState.postsCache[post.slug];
            setStatus('', false);
            Router.render();
          } else {
            setStatus(data.error || 'Invalid license key. Please try again.', true);
            unlockBtn.disabled = false;
            unlockBtn.innerHTML = '<i class="fa-solid fa-unlock"></i> Unlock';
          }
        } catch (err) {
          setStatus('Could not reach the license server. Check your connection.', true);
          unlockBtn.disabled = false;
          unlockBtn.innerHTML = '<i class="fa-solid fa-unlock"></i> Unlock';
        }
      };

      unlockBtn.addEventListener('click', doVerify);
      licenseInput.addEventListener('keydown', e => { if (e.key === 'Enter') doVerify(); });
    }

    // Code blocks: copy button + language label
    app.querySelectorAll('pre').forEach(pre => {
      const wrap = document.createElement('div');
      wrap.className = 'code-block';
      const bar = document.createElement('div');
      bar.className = 'code-block__bar';
      const lang = pre.querySelector('code')?.className.match(/language-(\w+)/)?.[1];
      const langLabel = Object.assign(document.createElement('span'), { className: 'code-lang', textContent: lang || '' });
      bar.appendChild(langLabel);
      const btn = document.createElement('button');
      btn.className = 'copy-btn';
      btn.innerHTML = `<i class="fa-regular fa-copy"></i> Copy`;
      btn.addEventListener('click', async () => {
        try { await navigator.clipboard.writeText(pre.textContent); } catch {
          try {
            const ta = Object.assign(document.createElement('textarea'), { value: pre.textContent });
            ta.style.cssText = 'position:fixed;opacity:0';
            document.body.appendChild(ta); ta.select(); document.execCommand('copy'); ta.remove();
          } catch { /* clipboard unavailable */ }
        }
        btn.innerHTML = `<i class="fa-solid fa-check"></i> Copied`;
        btn.classList.add('copied');
        setTimeout(() => { btn.innerHTML = `<i class="fa-regular fa-copy"></i> Copy`; btn.classList.remove('copied'); }, 2000);
      });
      bar.appendChild(btn);
      wrap.appendChild(bar);
      pre.parentNode.insertBefore(wrap, pre);
      wrap.appendChild(pre);
    });

    // Tables: Copy CSV button
    app.querySelectorAll('.post-body table, .paywall-fade table').forEach(table => {
      const wrap = document.createElement('div');
      wrap.className = 'table-wrap';
      table.parentNode.insertBefore(wrap, table);
      wrap.appendChild(table);
      const bar = document.createElement('div');
      bar.className = 'table-bar';
      const copyBtn = document.createElement('button');
      copyBtn.className = 'table-copy-btn btn';
      copyBtn.innerHTML = `<i class="fa-regular fa-copy"></i> Copy CSV`;
      copyBtn.addEventListener('click', async () => {
        const rows = [...table.querySelectorAll('tr')];
        const csv  = rows.map(r => [...r.querySelectorAll('th,td')]
          .map(c => `"${c.textContent.replace(/"/g, '""')}"`)
          .join(',')).join('\n');
        try { await navigator.clipboard.writeText(csv); } catch {
          try {
            const ta = Object.assign(document.createElement('textarea'), { value: csv });
            ta.style.cssText = 'position:fixed;opacity:0';
            document.body.appendChild(ta); ta.select(); document.execCommand('copy'); ta.remove();
          } catch { /* clipboard unavailable */ }
        }
        copyBtn.innerHTML = `<i class="fa-solid fa-check"></i> Copied`;
        copyBtn.classList.add('copied');
        setTimeout(() => { copyBtn.innerHTML = `<i class="fa-regular fa-copy"></i> Copy CSV`; copyBtn.classList.remove('copied'); }, 2000);
      });
      bar.appendChild(copyBtn);
      wrap.insertBefore(bar, table);
    });

    if (typeof Prism !== 'undefined') Prism.highlightAll();

    // ── Reading progress in page title ────────────────────────────
    const _titleBase = document.title;
    const _titleScroll = () => {
      const total = document.documentElement.scrollHeight - window.innerHeight;
      if (total <= 0) return;
      const pct = Math.round(window.scrollY / total * 100);
      document.title = pct > 2 && pct < 99 ? `${pct}% · ${post.title}` : _titleBase;
    };
    window._titleScrollHandler && window.removeEventListener('scroll', window._titleScrollHandler);
    window._titleScrollHandler = _titleScroll;
    window.addEventListener('scroll', _titleScroll, { passive: true });

    // ── Anchor deep-link toast ────────────────────────────────────
    if (location.hash) {
      const targetId = decodeURIComponent(location.hash.slice(1));
      const target = document.getElementById(targetId);
      if (target) {
        setTimeout(() => {
          target.scrollIntoView({ behavior: 'smooth', block: 'start' });
          UI.showToast(`<i class="fa-solid fa-link"></i> Jumped to: ${target.textContent.replace(/#$/, '').trim().slice(0, 40)}`);
        }, 350);
      }
    }

    window.scrollTo({ top: 0, behavior: 'instant' });

    // ── Ads — inject mid-post on free posts only ─────────────────
    if (!paywalled) {
      const postBody = app.querySelector('.post-body');
      if (postBody) {
        const paras = postBody.querySelectorAll('p');
        const insertAfter = paras[Math.floor(paras.length / 3)] || paras[0];
        if (insertAfter) {
          const adWrap = document.createElement('div');
          adWrap.className = 'ad-wrap';

          if (CONFIG.ADSENSE_CLIENT && CONFIG.ADSENSE_SLOT) {
            // ── Google AdSense unit ──────────────────────────────
            adWrap.innerHTML = `
              <ins class="adsbygoogle ad-unit"
                   style="display:block"
                   data-ad-client="${CONFIG.ADSENSE_CLIENT}"
                   data-ad-slot="${CONFIG.ADSENSE_SLOT}"
                   data-ad-format="auto"
                   data-full-width-responsive="true"></ins>`;
            insertAfter.after(adWrap);
            const pushAd = () => {
              try { (window.adsbygoogle = window.adsbygoogle || []).push({}); } catch(e) {}
            };
            if (!document.getElementById('adsense-script')) {
              const s = document.createElement('script');
              s.id = 'adsense-script';
              s.async = true;
              s.src = `https://pagead2.googlesyndication.com/pagead/js/adsbygoogle.js?client=${CONFIG.ADSENSE_CLIENT}`;
              s.crossOrigin = 'anonymous';
              s.onload = pushAd;
              document.head.appendChild(s);
            } else {
              // Script already loaded — push immediately
              pushAd();
            }

          } else if (CONFIG.HOUSE_AD_ENABLED && !AppState.isMember) {
            // ── House ad — skip if dismissed this session ────────
            if (sessionStorage.getItem(_key('house_ad_dismissed')) !== '1') {
            adWrap.innerHTML = `
              <div class="house-ad">
                <button class="house-ad__close" aria-label="Dismiss" title="Dismiss">×</button>
                <div class="house-ad__eyebrow">
                  <i class="fa-solid fa-star"></i>
                  <span>Members Only</span>
                </div>
                <h3 class="house-ad__headline">${CONFIG.HOUSE_AD_TEXT}</h3>
                <div class="house-ad__footer">
                  <a href="${CONFIG.MEMBERSHIP_URL}" target="_blank" rel="noopener" class="house-ad__cta">
                    <i class="fa-solid fa-unlock"></i> ${CONFIG.HOUSE_AD_CTA}
                  </a>
                  <span class="house-ad__price">${CONFIG.MEMBERSHIP_PRICE}</span>
                </div>
              </div>`;
            insertAfter.after(adWrap);
            adWrap.querySelector('.house-ad__close')?.addEventListener('click', () => {
              adWrap.style.display = 'none';
              sessionStorage.setItem(_key('house_ad_dismissed'), '1');
            });
            }
          }
        }
      }
    }
    // Smooth scroll for in-page anchor links
    app.querySelectorAll('a[href^="#"]').forEach(a => {
      a.addEventListener('click', e => {
        e.preventDefault();
        const id = decodeURIComponent(a.getAttribute('href').slice(1));
        document.getElementById(id)?.scrollIntoView({ behavior: 'smooth', block: 'start' });
      });
    });
  }
};

// =========================================
// 5. ROUTER
// =========================================
const Router = {
  go(slug) {
    history.pushState({ slug }, '', `/post/${encodeURIComponent(slug)}`);
    this.render();
  },
  back(tag) {
    this.setQuery({ tag: tag || null, page: 1 });
  },
  getSlug() {
    // Handle /posts/slug (raw GitHub Pages path) → silently rewrite to /post/slug
    const rawMd = location.pathname.match(/^\/posts\/(.+?)(?:\.md)?$/);
    if (rawMd) {
      const slug = decodeURIComponent(rawMd[1]);
      history.replaceState({}, '', `/post/${encodeURIComponent(slug)}`);
      return slug;
    }
    const m = location.pathname.match(/^\/post\/(.+)$/);
    return m ? decodeURIComponent(m[1]) : null;
  },
  getParams() {
    const qs = new URLSearchParams(location.search);
    return {
      tag:  qs.get('tag') || null,
      page: Math.max(1, parseInt(qs.get('page')) || 1)
    };
  },
  setQuery({ tag, page } = {}) {
    const qs = new URLSearchParams();
    if (tag && tag !== 'all') qs.set('tag', tag);
    if (page > 1) qs.set('page', page);
    history.pushState({}, '', qs.toString() ? `/?${qs.toString()}` : '/');
    this.render();
  },
  async render() {
    const slug    = this.getSlug();
    const indexEl = document.getElementById('view-index');
    const postEl  = document.getElementById('view-post');
    const readBar = document.getElementById('reading-bar');

    // ── Bookmarks view (/bookmarks) ────────────────────────────
    if (location.pathname === '/bookmarks') {
      indexEl.style.display = 'none';
      postEl.style.display  = 'none';
      if (readBar) { readBar.style.display = 'none'; readBar.style.width = '0%'; }
      document.title = `Bookmarks — ${CONFIG.SITE_TITLE}`;
      let bmView = document.getElementById('view-bookmarks');
      if (!bmView) {
        bmView = document.createElement('section');
        bmView.id = 'view-bookmarks';
        bmView.className = 'container';
        document.getElementById('main-content').appendChild(bmView);
      }
      bmView.style.display = '';
      const savedSlugs = AppState.posts
        .filter(p => localStorage.getItem(_key('bm:' + p.slug)) === '1')
        .map(p => p.slug);
      const savedPosts = savedSlugs.map(sl => AppState.posts.find(p => p.slug === sl)).filter(Boolean);
      const recentPosts = (CONFIG.RECENTLY_VIEWED_COUNT || 0) > 0 ? RecentlyViewed.getPosts() : [];
      bmView.innerHTML = `
        <div class="section-header" style="margin-top:var(--space-12)">
          <h2 class="section-header__title"><i class="fa-solid fa-bookmark"></i> Bookmarks</h2>
          <div class="section-header__line"></div>
        </div>
        ${savedPosts.length === 0
          ? `<div class="empty-state"><i class="fa-regular fa-bookmark empty-icon"></i><h3>No bookmarks yet</h3><p>Hit the bookmark icon on any post or card to save it here.</p><button class="btn primary" id="bm-back-btn"><i class="fa-solid fa-arrow-left"></i> Browse posts</button></div>`
          : `<div class="grid" id="bm-grid" role="list"></div>`}
        ${recentPosts.length > 0 ? `
          <div class="section-header" style="margin-top:var(--space-10)">
            <h2 class="section-header__title" style="font-size:1.1rem"><i class="fa-solid fa-clock-rotate-left"></i> Recently Viewed</h2>
            <div class="section-header__line"></div>
          </div>
          <ul class="recently-viewed-list">
            ${recentPosts.map(p => `
              <li class="recently-viewed-item">
                <button class="recently-viewed-btn" data-slug="${Utils.escapeHtml(p.slug)}">
                  <span class="recently-viewed-tag">${Utils.tagIcon(p.tag)}</span>
                  <span class="recently-viewed-title">${Utils.escapeHtml(p.title)}</span>
                  <span class="recently-viewed-meta"><i class="fa-regular fa-clock"></i> ${Utils.escapeHtml(p.readTime)}</span>
                </button>
              </li>`).join('')}
          </ul>` : ''}`;
      if (savedPosts.length) {
        const bmGrid = bmView.querySelector('#bm-grid');
        if (bmGrid) {
          bmGrid.innerHTML = savedPosts.map((p, i) => {
            const visual = p.cover
              ? `<img src="${Utils.escapeHtml(p.cover)}" alt="${Utils.escapeHtml(p.title)}" class="card__cover-img" loading="lazy">`
              : `<i class="fa-solid fa-file-lines card__icon" aria-hidden="true"></i>`;
            const isBookmarked = true; // all cards here are bookmarked
            return `<article class="card" role="listitem" data-idx="${i}">
              <div class="card__visual">${visual}</div>
              <div class="card__content">
                <span class="card__tag" data-tag="${Utils.escapeHtml(p.tag)}"><i class="${TAG_ICONS[p.tag] || TAG_ICONS.Post}"></i> ${Utils.escapeHtml(p.tag)}</span>
                <h2 class="card__title">${Utils.escapeHtml(p.title)}</h2>
                <p class="card__excerpt">${Utils.escapeHtml(p.excerpt)}</p>
                <div class="card__footer">
                  <span class="card__author"><i class="fa-solid fa-user-pen"></i> ${Utils.escapeHtml(p.author)}</span>
                  <span class="card__meta">
                    <i class="fa-regular fa-calendar"></i> ${Utils.fmtDateShort(p.date)}
                    <span class="meta-dot">·</span><i class="fa-regular fa-clock"></i> ${Utils.escapeHtml(p.readTime)}
                  </span>
                  <button class="card__bookmark bookmarked" data-bm="${Utils.escapeHtml(p.slug)}" aria-label="Remove bookmark" title="Remove bookmark"><i class="fa-solid fa-bookmark"></i></button>
                </div>
              </div>
            </article>`;
          }).join('');
          bmGrid.querySelectorAll('.card').forEach((card, i) => {
            card.setAttribute('tabindex', '0');
            card.setAttribute('aria-label', `Read: ${savedPosts[i].title}`);
            card.addEventListener('click', e => {
              const bmBtn = e.target.closest('.card__bookmark');
              if (bmBtn) {
                e.stopPropagation();
                const slug = bmBtn.dataset.bm;
                localStorage.setItem(_key('bm:' + slug), '0');
                card.remove();
                if (!bmGrid.children.length) bmView.querySelector('.section-header')?.insertAdjacentHTML('afterend', `<div class="empty-state"><i class="fa-regular fa-bookmark empty-icon"></i><h3>No bookmarks yet</h3><p>Hit the bookmark icon on any post or card to save it here.</p><button class="btn primary" id="bm-back-btn2"><i class="fa-solid fa-arrow-left"></i> Browse posts</button></div>`);
                bmView.querySelector('#bm-back-btn2')?.addEventListener('click', () => Router.back());
                UI.showToast('<i class="fa-regular fa-bookmark"></i> Removed from bookmarks');
                return;
              }
              Router.go(savedPosts[i].slug);
            });
            card.addEventListener('keydown', e => {
              if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); Router.go(savedPosts[i].slug); }
            });
          });
        }
      }
      bmView.querySelector('#bm-back-btn')?.addEventListener('click', () => Router.back());
      bmView.querySelectorAll('.recently-viewed-btn[data-slug]').forEach(btn => {
        btn.addEventListener('click', () => Router.go(btn.dataset.slug));
      });
      document.querySelectorAll('.nav a, .mobile-nav a').forEach(a =>
        a.classList.toggle('active', a.getAttribute('href') === '/bookmarks'));
      return;
    }

    // Hide bookmarks view if visible
    const bmView2 = document.getElementById('view-bookmarks');
    if (bmView2) bmView2.style.display = 'none';

    // Close search bar only when navigating to a post, not on index re-renders (e.g. search input)
    const searchBar   = Utils.qs('#search-bar');
    const searchInput = Utils.qs('#search-input');
    if (slug && searchBar?.classList.contains('open')) {
      searchBar.classList.remove('open');
      searchBar.setAttribute('aria-hidden', 'true');
      if (searchInput) { searchInput.value = ''; AppState.search = ''; }
    }

    if (slug) {
      // ── Post view ─────────────────────────────────────────
      indexEl.style.display = 'none';
      postEl.style.display  = '';
      if (readBar) readBar.style.display = '';

      document.querySelectorAll('.nav a, .mobile-nav a').forEach(a =>
        a.classList.toggle('active', a.getAttribute('href') === '/')
      );

      Utils.qs('#post-article').innerHTML =
        `<div class="loading-spinner"><div class="spinner"></div></div>`;

      try {
        const post = await DataLoader.fetchBody(slug);
        if (post) {
          Renderer.renderPost(post);
        } else {
          throw new Error('post not found');
        }
      } catch (err) {
        console.error("[Router] fetchBody failed:", err?.message || err);
        Utils.qs('#post-article').innerHTML = `
          <div class="empty-state">
            <i class="fa-solid fa-file-circle-xmark empty-icon"></i>
            <h3>Post not found</h3>
            <p>The post you're looking for doesn't exist or failed to load.</p>
            <button class="btn primary" id="err-back-btn">
              <i class="fa-solid fa-arrow-left"></i> Back to posts
            </button>
          </div>`;
        Utils.qs('#err-back-btn')?.addEventListener('click', () => Router.back());
      }
    } else {
      // ── Index view ────────────────────────────────────────
      indexEl.style.display = '';
      postEl.style.display  = 'none';
      if (readBar) { readBar.style.display = 'none'; readBar.style.width = '0%'; }

      // Scroll to top when filter or page changes (not on search input — that's live)
      if (!AppState.search) window.scrollTo({ top: 0, behavior: 'instant' });

      // AppState.search is kept in sync by the input event handler; no re-read needed here.

      // Reset title + meta to homepage defaults
      document.title = `${CONFIG.SITE_TITLE} — ${CONFIG.SITE_TAGLINE}`;
      document.getElementById('canonical-url')?.setAttribute('href', `${CONFIG.BLOG_URL}/`);
      document.getElementById('og-type')?.setAttribute('content', 'website');
      document.getElementById('og-url')?.setAttribute('content', `${CONFIG.BLOG_URL}/`);
      ['og-title', 'tw-title'].forEach(id =>
        Utils.qs(`#${id}`)?.setAttribute('content', `${CONFIG.SITE_TITLE} — ${CONFIG.SITE_TAGLINE}`));
      ['og-desc', 'tw-desc'].forEach(id =>
        Utils.qs(`#${id}`)?.setAttribute('content', CONFIG.SITE_DESCRIPTION));

      const { tag, page } = this.getParams();
      AppState.filter = tag || 'all';
      AppState.pagination.page = page;

      document.querySelectorAll('.nav a, .mobile-nav a').forEach(a => {
        const href = a.getAttribute('href');
        const hrefTag = href?.includes('?tag=') ? href.split('?tag=')[1].toLowerCase() : null;
        const activeTag = tag ? tag.toLowerCase() : null;
        a.classList.toggle('active', hrefTag === activeTag || (!hrefTag && !tag && href === '/'));
      });

      document.querySelectorAll('.chip').forEach(chip =>
        chip.classList.toggle('active', chip.dataset.tag.toLowerCase() === AppState.filter.toLowerCase())
      );

      let filtered = AppState.filter === 'all'
        ? AppState.posts
        : AppState.posts.filter(p => p.tag.toLowerCase() === AppState.filter.toLowerCase());

      if (AppState.search) {
        const q = AppState.search.toLowerCase();
        // Use Fuse.js fuzzy results if available, else fall back to indexOf
        if (typeof Fuse !== 'undefined' && CONFIG.FUZZY_SEARCH_ENABLED && q.length >= 2) {
          const fuse = new Fuse(filtered, {
            keys: ['title', 'excerpt', 'tag', 'author'],
            threshold: 0.35,
            ignoreLocation: true,
            minMatchCharLength: 2,
          });
          filtered = fuse.search(q).map(r => r.item);
        } else {
          filtered = filtered.filter(p => {
            if (p.title.toLowerCase().includes(q)) return true;
            if (p.excerpt.toLowerCase().includes(q)) return true;
            if (p.tag.toLowerCase().includes(q)) return true;
            // Only search body content that is already cached in memory.
            // Never trigger on-demand fetches during search — that would
            // fire hundreds of requests on every keystroke.
            if (p.paywalled && !AppState.isMember) return false;
            const cachedBody = AppState.postsCache[p.slug]?.body;
            return cachedBody ? cachedBody.toLowerCase().includes(q) : false;
          });
        }
      }

      const { perPage } = AppState.pagination;
      const totalPages = Math.max(1, Math.ceil(filtered.length / perPage));
      if (AppState.pagination.page > totalPages) AppState.pagination.page = totalPages;
      const start   = (AppState.pagination.page - 1) * perPage;
      const visible = filtered.slice(start, start + perPage);

      const showFeatured = AppState.filter === 'all' && AppState.pagination.page === 1 && !AppState.search;

      // Hero already features posts[0], so strip it from the grid
      const gridPosts = (showFeatured && visible.length > 1)
        ? visible.slice(1)
        : visible;

      const st = Utils.qs('#section-title');
      if (st) st.textContent = AppState.search
        ? `Results for "${AppState.search}"`
        : (AppState.filter === 'all' ? 'Latest Posts' : AppState.filter);

      const heroEl = Utils.qs('.hero');
      const heroVisible = !AppState.search && AppState.filter === 'all';
      if (heroEl) {
        if (heroVisible) {
          heroEl.style.animation = '';
          heroEl.style.display   = '';
        } else {
          heroEl.style.display = 'none';
        }
      }

      Renderer.renderPosts(gridPosts, showFeatured);
      Renderer.renderPagination(filtered.length, perPage, AppState.pagination.page);

      // (Scroll to results is handled once by the search toggle, not on every re-render)
    }
  }
};

// =========================================
// 6. UI & EVENTS
// =========================================
const UI = {
  showError(title, detail, code) {
    const grid = Utils.qs('#posts-grid');
    if (!grid) return;
    grid.innerHTML = `<div class="empty-state"><i class="fa-solid fa-triangle-exclamation empty-icon" style="color:var(--color-error)"></i><h3>${Utils.escapeHtml(title)}</h3><p>${Utils.escapeHtml(detail)}</p>${code ? `<pre><code>${Utils.escapeHtml(code)}</code></pre>` : ''}</div>`;
  },

  initTheme() {
    const btn  = Utils.qs('#theme-btn');
    const icon = Utils.qs('#theme-icon');
    const PRISM_DARK  = 'https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism-tomorrow.min.css';
    const PRISM_LIGHT = 'https://cdnjs.cloudflare.com/ajax/libs/prism/1.29.0/themes/prism.min.css';
    const apply = t => {
      document.documentElement.setAttribute('data-theme', t);
      AppState.theme = t;
      localStorage.setItem(_key('theme'), t);
      if (icon) icon.className = t === 'dark' ? 'fa-solid fa-sun' : 'fa-solid fa-moon';
      const prismLink = document.getElementById('prism-theme');
      if (prismLink) prismLink.href = t === 'dark' ? PRISM_DARK : PRISM_LIGHT;
      // Update PWA theme-color
      const pwaTc = document.getElementById('pwa-theme-color');
      if (pwaTc) pwaTc.content = t === 'light' ? '#faf9f7' : '#161514';
      // Sync Giscus iframe theme if it's visible on the page
      if (!CONFIG.GISCUS_THEME) {
        const giscusFrame = document.querySelector('iframe.giscus-frame');
        if (giscusFrame) {
          giscusFrame.contentWindow?.postMessage(
            { giscus: { setConfig: { theme: t === 'dark' ? 'dark_dimmed' : 'light' } } },
            'https://giscus.app'
          );
        }
      }
    };
    apply(AppState.theme);
    btn?.addEventListener('click', () =>
      apply(document.documentElement.getAttribute('data-theme') === 'dark' ? 'light' : 'dark')
    );
    matchMedia('(prefers-color-scheme: dark)').addEventListener('change', e => {
      if (!localStorage.getItem(_key('theme'))) apply(e.matches ? 'dark' : 'light');
    });
  },

  initMenu() {
    const btn = Utils.qs('#menu-toggle');
    const nav = Utils.qs('#mobile-nav');
    btn?.addEventListener('click', () => {
      const open = nav?.classList.toggle('open');
      btn.classList.toggle('open', open);
      btn.setAttribute('aria-expanded', open ? 'true' : 'false');
      nav?.setAttribute('aria-hidden', open ? 'false' : 'true');
    });
    nav?.addEventListener('click', e => {
      if (e.target.tagName === 'A' || e.target.closest('a')) {
        nav.classList.remove('open');
        btn.classList.remove('open');
        btn.setAttribute('aria-expanded', 'false');
        nav.setAttribute('aria-hidden', 'true');
      }
    });
  },

  initSearch() {
    const toggleBtn = Utils.qs('#search-toggle');
    const closeBtn  = Utils.qs('#search-close');
    const searchBar = Utils.qs('#search-bar');
    const input     = Utils.qs('#search-input');

    // ── Fuse.js fuzzy search — lazy-loaded on first open ─────────
    let fuseInstance = null;
    const loadFuse = () => {
      if (!CONFIG.FUZZY_SEARCH_ENABLED || fuseInstance || typeof Fuse !== 'undefined') return;
      if (typeof Fuse !== 'undefined') return; // already loaded
      const s = document.createElement('script');
      s.src = 'https://cdn.jsdelivr.net/npm/fuse.js@7/dist/fuse.min.js';
      s.onload = () => {
        fuseInstance = new Fuse(AppState.posts, {
          keys: ['title', 'excerpt', 'tag', 'author'],
          threshold: 0.35,
          ignoreLocation: true,
          minMatchCharLength: 2,
        });
      };
      document.head.appendChild(s);
    };

    const getFuseResults = (q) => {
      if (!CONFIG.FUZZY_SEARCH_ENABLED) return null;
      if (typeof Fuse === 'undefined') return null;
      if (!fuseInstance) {
        fuseInstance = new Fuse(AppState.posts, {
          keys: ['title', 'excerpt', 'tag', 'author'],
          threshold: 0.35,
          ignoreLocation: true,
          minMatchCharLength: 2,
        });
      }
      return fuseInstance.search(q).map(r => r.item);
    };

    toggleBtn?.addEventListener('click', () => {
      const open = searchBar.classList.toggle('open');
      searchBar.setAttribute('aria-hidden', open ? 'false' : 'true');
      if (open) {
        loadFuse();
        setTimeout(() => input?.focus(), 80);
      }
    });
    closeBtn?.addEventListener('click', () => {
      searchBar.classList.remove('open');
      searchBar.setAttribute('aria-hidden', 'true');
      if (input) { input.value = ''; input.dispatchEvent(new Event('input')); }
    });
    input?.addEventListener('input', e => {
      const raw = e.target.value;
      const q   = raw.toLowerCase().trim();
      AppState.search = q;
      if (Router.getSlug()) return;
      AppState.pagination.page = 1;
      const savedValue  = raw;
      const savedCursor = e.target.selectionStart;
      Router.render();
      // Restore focus + cursor after render re-paints the DOM
      if (input) {
        input.value = savedValue;
        input.focus();
        try { input.setSelectionRange(savedCursor, savedCursor); } catch {}
      }
      const live = Utils.qs('#search-live');
      if (live && q) {
        // Count using Fuse if available, else fall back to indexOf
        const fuseResults = getFuseResults(q);
        const count = fuseResults
          ? fuseResults.length
          : AppState.posts.filter(p => {
              if (p.title.toLowerCase().includes(q))   return true;
              if (p.excerpt.toLowerCase().includes(q)) return true;
              if (p.tag.toLowerCase().includes(q))     return true;
              if (p.paywalled && !AppState.isMember)   return false;
              const cachedBody = AppState.postsCache[p.slug]?.body;
              return cachedBody ? cachedBody.toLowerCase().includes(q) : false;
            }).length;
        live.textContent = `${count} result${count !== 1 ? 's' : ''} for "${raw}"`;
      } else if (live) {
        live.textContent = '';
      }
    });
    document.addEventListener('keydown', e => {
      if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
        e.preventDefault();
        searchBar.classList.add('open');
        searchBar.setAttribute('aria-hidden', 'false');
        setTimeout(() => input?.focus(), 80);
      }
      if (e.key === 'Escape' && searchBar.classList.contains('open')) {
        searchBar.classList.remove('open');
        searchBar.setAttribute('aria-hidden', 'true');
        if (input) { input.value = ''; input.dispatchEvent(new Event('input')); }
      }
    });
  },

  initFilters() {
    const bar = Utils.qs('#tag-bar');
    if (!bar) return;
    const tags = ['all', ...new Set(AppState.posts.map(p => p.tag))];
    const tagCounts = AppState.posts.reduce((acc, p) => { acc[p.tag] = (acc[p.tag] || 0) + 1; return acc; }, {});
    bar.innerHTML = tags.map(t => {
      const count = t === 'all' ? AppState.posts.length : (tagCounts[t] || 0);
      return `<button class="chip ${t === AppState.filter ? 'active' : ''}" data-tag="${t}">${t !== 'all' ? Utils.tagIcon(t) + ' ' : ''}${t === 'all' ? 'All' : t}<span class="chip__count">${count}</span></button>`;
    }).join('');
    bar.addEventListener('click', e => {
      const btn = e.target.closest('.chip');
      if (!btn) return;
      bar.querySelectorAll('.chip').forEach(b => b.classList.remove('active'));
      btn.classList.add('active');
      AppState.search = '';
      const input = Utils.qs('#search-input');
      if (input) input.value = '';
      const live = Utils.qs('#search-live');
      if (live) live.textContent = '';
      Router.setQuery({ tag: btn.dataset.tag === 'all' ? null : btn.dataset.tag, page: 1 });
    });
  },

  initBackTop() {
    const btn = Utils.qs('#back-top');
    if (!btn) return;
    const _bto = CONFIG.BACK_TO_TOP_OFFSET || 400; window.addEventListener('scroll', () => btn.classList.toggle('show', window.scrollY > _bto), { passive: true });
    btn.addEventListener('click', () => scrollTo({ top: 0, behavior: 'smooth' }));
  },

  initReadingBar() {
    const bar = Utils.qs('#reading-bar');
    if (!bar) return;
    window.addEventListener('scroll', () => {
      const total = document.documentElement.scrollHeight - window.innerHeight;
      bar.style.width = total > 0 ? (window.scrollY / total * 100) + '%' : '0%';
    }, { passive: true });
  },

  initLogoLink() {
    document.addEventListener('click', e => {
      const a = e.target.closest('a[href]');
      if (!a) return;
      const href = a.getAttribute('href');
      if (!href || href.startsWith('http') || href.startsWith('//') || href.startsWith('#') || href.startsWith('mailto:') || href.startsWith('tel:')) return;
      // Close the search bar before navigating
      const searchBar = Utils.qs('#search-bar');
      const searchInput = Utils.qs('#search-input');
      if (searchBar?.classList.contains('open')) {
        searchBar.classList.remove('open');
        searchBar.setAttribute('aria-hidden', 'true');
        if (searchInput) { searchInput.value = ''; AppState.search = ''; }
      }
      e.preventDefault();
      if (location.pathname + location.search !== href) {
        history.pushState({}, '', href);
        Router.render();
      }
    });
  },

  showToast(msg) {
    const toast = Object.assign(document.createElement('div'), {
      className: 'toast',
      innerHTML: msg
    });
    document.body.appendChild(toast);
    setTimeout(() => toast.classList.add('show'), 10);
    setTimeout(() => { toast.classList.remove('show'); setTimeout(() => toast.remove(), 300); }, CONFIG.TOAST_DURATION || 2500);
  },

  copyToClipboard(text) {
    if (navigator.clipboard && navigator.clipboard.writeText) {
      return navigator.clipboard.writeText(text).catch(() => {
        const ta = Object.assign(document.createElement('textarea'), { value: text });
        ta.style.cssText = 'position:fixed;opacity:0;top:0;left:0';
        document.body.appendChild(ta); ta.focus(); ta.select();
        try { document.execCommand('copy'); } catch {}
        ta.remove();
      });
    }
    const ta = Object.assign(document.createElement('textarea'), { value: text });
    ta.style.cssText = 'position:fixed;opacity:0;top:0;left:0';
    document.body.appendChild(ta); ta.focus(); ta.select();
    try { document.execCommand('copy'); } catch {}
    ta.remove();
    return Promise.resolve();
  },

  initKeyboardShortcuts() {
    if (CONFIG.KEYBOARD_SHORTCUTS_ENABLED === false) return;
    // Wire the ? button in header
    document.getElementById('shortcuts-hint')?.addEventListener('click', () => UI.showShortcutsModal());
    let gPressed = false, gTimer;
    document.addEventListener('keydown', e => {
      // Skip if user is typing in an input/textarea
      if (['INPUT', 'TEXTAREA', 'SELECT'].includes(document.activeElement.tagName)) return;
      if (document.activeElement.isContentEditable) return;

      // ? → show shortcuts modal
      if (e.key === '?' && !e.ctrlKey && !e.metaKey) {
        e.preventDefault();
        UI.showShortcutsModal();
        return;
      }

      // G-sequence shortcuts: G then H / B / P
      if (e.key === 'g' || e.key === 'G') {
        gPressed = true;
        clearTimeout(gTimer);
        gTimer = setTimeout(() => { gPressed = false; }, 1500);
        return;
      }
      if (gPressed) {
        gPressed = false; clearTimeout(gTimer);
        if (e.key === 'h' || e.key === 'H') { e.preventDefault(); history.pushState({}, '', '/'); Router.render(); return; }
        if ((e.key === 'b' || e.key === 'B') && CONFIG.BOOKMARKS_ENABLED) { e.preventDefault(); history.pushState({}, '', '/bookmarks'); Router.render(); return; }
      }

      // Arrow keys for prev/next post
      if (e.key === 'ArrowLeft') {
        const prev = document.getElementById('nav-prev');
        if (prev) { e.preventDefault(); prev.click(); }
      }
      if (e.key === 'ArrowRight') {
        const next = document.getElementById('nav-next');
        if (next) { e.preventDefault(); next.click(); }
      }

      // L → like current post
      if (e.key === 'l' || e.key === 'L') {
        const likeBtn = document.getElementById('like-btn');
        if (likeBtn) { e.preventDefault(); likeBtn.click(); }
      }

      // B → bookmark current post
      if (e.key === 'b' || e.key === 'B') {
        const bmBtn = document.getElementById('post-bookmark-btn');
        if (bmBtn) { e.preventDefault(); bmBtn.click(); }
      }
    });
  },

  showShortcutsModal() {
    if (document.getElementById('shortcuts-modal')) return;
    const modal = document.createElement('div');
    modal.id = 'shortcuts-modal';
    modal.className = 'shortcuts-modal';
    modal.setAttribute('role', 'dialog');
    modal.setAttribute('aria-modal', 'true');
    modal.setAttribute('aria-label', 'Keyboard shortcuts');
    modal.innerHTML = `
      <div class="shortcuts-modal__card">
        <div class="shortcuts-modal__header">
          <h2 class="shortcuts-modal__title"><i class="fa-solid fa-keyboard"></i> Keyboard Shortcuts</h2>
          <button class="btn-icon shortcuts-modal__close" aria-label="Close">
            <i class="fa-solid fa-xmark"></i>
          </button>
        </div>
        <div class="shortcuts-modal__grid">
          <div class="shortcuts-modal__group">
            <h3>Navigation</h3>
            <div class="shortcut-row"><kbd>G</kbd><kbd>H</kbd><span>Go home</span></div>
            <div class="shortcut-row"><kbd>G</kbd><kbd>B</kbd><span>Go to bookmarks</span></div>
            <div class="shortcut-row"><kbd>←</kbd><kbd>→</kbd><span>Older / Newer post</span></div>
          </div>
          <div class="shortcuts-modal__group">
            <h3>Search</h3>
            <div class="shortcut-row"><kbd>Ctrl</kbd><kbd>K</kbd><span>Open search</span></div>
            <div class="shortcut-row"><kbd>Esc</kbd><span>Close search</span></div>
          </div>
          <div class="shortcuts-modal__group">
            <h3>Post actions</h3>
            <div class="shortcut-row"><kbd>L</kbd><span>Like post</span></div>
            <div class="shortcut-row"><kbd>B</kbd><span>Bookmark post</span></div>
          </div>
          <div class="shortcuts-modal__group">
            <h3>Interface</h3>
            <div class="shortcut-row"><kbd>?</kbd><span>Show this panel</span></div>
          </div>
        </div>
      </div>`;
    document.body.appendChild(modal);
    modal.querySelector('.shortcuts-modal__close').addEventListener('click', () => modal.remove());
    modal.addEventListener('click', e => { if (e.target === modal) modal.remove(); });
    document.addEventListener('keydown', function esc(e) {
      if (e.key === 'Escape') { modal.remove(); document.removeEventListener('keydown', esc); }
    });
    // Focus trap
    setTimeout(() => modal.querySelector('.shortcuts-modal__close')?.focus(), 50);
  },

  share(post) {
    const url   = location.href;
    const title = post ? `${post.title} — ${CONFIG.SITE_TITLE}` : document.title;
    const text  = post?.excerpt || '';
    if (navigator.share) {
      navigator.share({ title, text, url }).catch(err => {
        if (err && err.name !== 'AbortError') {
          UI.copyToClipboard(url).then(() =>
            UI.showToast('<i class="fa-solid fa-check"></i> Link copied')
          );
        }
      });
    } else {
      UI.copyToClipboard(url).then(() =>
        UI.showToast('<i class="fa-solid fa-check"></i> Link copied')
      );
    }
  }
};

// =========================================
// 7. BOOTSTRAP
// =========================================
document.addEventListener('DOMContentLoaded', async () => {
  Renderer.applyBranding();
  UI.initTheme();
  UI.initMenu();
  UI.initBackTop();
  UI.initReadingBar();
  UI.initSearch();
  UI.initLogoLink();
  UI.initKeyboardShortcuts();
  ReadingStreak.update();
  ReadingStreak.render();

  const loadGrid = Utils.qs('#posts-grid');
  if (loadGrid) loadGrid.innerHTML = '<div class="loading-spinner"><div class="spinner"></div></div>';

  const posts  = await DataLoader.load();
  const loader = Utils.qs('#page-loader');

  if (posts) {
    AppState.posts = posts;
    Renderer.renderHero(posts);
    UI.initFilters();
    Router.render();
  }

  // Dismiss full-page loader
  if (loader) {
    const bar = loader.querySelector('.loader__bar');
    if (bar) { bar.style.animation = 'none'; bar.style.width = '100%'; }
    requestAnimationFrame(() => {
      setTimeout(() => loader.classList.add('hidden'), 80);
    });
  }

  window.addEventListener('popstate', () => {
    const mobileNav = Utils.qs('#mobile-nav');
    const menuBtn   = Utils.qs('#menu-toggle');
    if (mobileNav?.classList.contains('open')) {
      mobileNav.classList.remove('open');
      menuBtn?.classList.remove('open');
      menuBtn?.setAttribute('aria-expanded', 'false');
      mobileNav.setAttribute('aria-hidden', 'true');
    }
    // Close search bar and clear stale search state on back/forward navigation
    const searchBar   = Utils.qs('#search-bar');
    const searchInput = Utils.qs('#search-input');
    if (searchBar?.classList.contains('open')) {
      searchBar.classList.remove('open');
      searchBar.setAttribute('aria-hidden', 'true');
    }
    if (searchInput) { searchInput.value = ''; }
    AppState.search = '';
    Router.render();
  });
});
